#!/bin/bash
# 支持 Sing-box(VLESS+Reality/SS/Hysteria2)、UDP2RAW、KCPTUN 的部署与串联
# Generated by github.com/halibotee

SCRIPT_VERSION="0.8.11"

# 启用严格模式 (未定义变量/管道中间错误会报错)
# 不启用 -e: 脚本为交互式, 大量 cmd1; cmd2 与 if ! cmd 模式
set -uo pipefail

# KCPTUN 回退版本号 (下载源走 halibotee/scripts 仓库, 不依赖任何官方源)
KCPTUN_FALLBACK_RELEASE="20260101"

# 版本自增: 脚本内调用 bump_version [patch|minor|major]
# 或 CLI: bash ax-singbox-proxy.sh --bump-version=patch|minor|major
bump_version() {
    local level=${1:-patch}
    local script_path="${BASH_SOURCE[0]}"
    local current=$SCRIPT_VERSION
    IFS='.' read -r major minor patch <<< "$current"
    major=${major:-0}; minor=${minor:-0}; patch=${patch:-0}
    case "$level" in
        major) major=$((major+1)); minor=0; patch=0 ;;
        minor) minor=$((minor+1)); patch=0 ;;
        patch|*) patch=$((patch+1)) ;;
    esac
    local new="${major}.${minor}.${patch}"
    local tmpf
    tmpf=$(umask 077 && mktemp) || { echo "[ERR] 无法创建临时文件"; return 1; }
    chmod 600 "$tmpf"
    sed -E "s/^SCRIPT_VERSION=.*/SCRIPT_VERSION=\"${new}\"/" "$script_path" > "$tmpf" \
        && mv "$tmpf" "$script_path" \
        || { rm -f "$tmpf"; echo "[ERR] 写入版本失败"; return 1; }
    SCRIPT_VERSION=$new
    echo "[OK] 版本已更新: $current -> $new"
}

# CLI: --bump-version=<patch|minor|major>
if [[ "${1:-}" == --bump-version=* ]]; then
    bump_version "${1#--bump-version=}"
    exit 0
fi

# 检测操作系统
if [[ -f /etc/redhat-release ]]; then
release="Centos"
elif cat /etc/issue | grep -q -E -i "debian"; then
release="Debian"
elif cat /etc/issue | grep -q -E -i "ubuntu"; then
release="Ubuntu"
elif cat /etc/issue | grep -q -E -i "centos|red hat|redhat"; then
release="Centos"
elif cat /proc/version | grep -q -E -i "debian"; then
release="Debian"
elif cat /proc/version | grep -q -E -i "ubuntu"; then
release="Ubuntu"
elif cat /proc/version | grep -q -E -i "centos|red hat|redhat"; then
release="Centos"
else 
red "不支持当前的系统，请选择使用Ubuntu,Debian,Centos系统。" && exit
fi
vsid=$(grep -i version_id /etc/os-release | cut -d \" -f2 | cut -d . -f1)
op=$(cat /etc/redhat-release 2>/dev/null || cat /etc/os-release 2>/dev/null | grep -i pretty_name | cut -d \" -f2)
version=$(uname -r | cut -d "-" -f1)
main=$(uname -r | cut -d "." -f1)
minor=$(uname -r | cut -d "." -f2)
vi=$(systemd-detect-virt)
case "$release" in
"Centos") yumapt='yum -y';;
"Ubuntu"|"Debian") yumapt="apt-get -y";;
esac
cpujg(){
case $(uname -m) in
aarch64) cpu=arm64;;
x86_64) cpu=amd64;;
*) red "目前脚本不支持$(uname -m)架构" && exit;;
esac
}

