# -----------------------------------------------------------------------------
# 终端颜色输出函数
# -----------------------------------------------------------------------------
green(){ echo -e "\033[0;32m$1\033[0m"; }  # 输出绿色文本
red(){ echo -e "\033[0;31m$1\033[0m"; }    # 输出红色文本 (用于错误)
yellow(){ echo -e "\033[0;33m$1\033[0m"; } # 输出黄色文本 (用于警告/提示)
cyan(){ echo -e "\033[0;36m$1\033[0m"; }   # 输出青色文本 (用于信息)
bold(){ echo -e "\033[1m$1\033[0m"; }      # 输出粗体文本
dim(){ echo -e "\033[2m$1\033[0m"; }       # 输出淡化(灰色)文本

# -----------------------------------------------------------------------------
# 日志记录函数
# -----------------------------------------------------------------------------
log(){ echo -e "[$(date '+%H:%M:%S')] $(bold "$1")"; }

# -----------------------------------------------------------------------------
# 检查是否已安装任何实例
# -----------------------------------------------------------------------------
is_installed(){
    [[ -d "$KCP_INSTALL_DIR" ]] && find "$KCP_INSTALL_DIR" -maxdepth 1 -name '*.json' 2>/dev/null | grep -q . && return 0
    [[ -d "$UDP2RAW_INSTALL_DIR" ]] && find "$UDP2RAW_INSTALL_DIR" -maxdepth 1 -name '*.conf' 2>/dev/null | grep -q . && return 0
    [[ -d "$SINGBOX_INSTALL_DIR" ]] && find "$SINGBOX_INSTALL_DIR" -maxdepth 1 -name '*.json' 2>/dev/null | grep -q . && return 0
    return 1
}

PUBLIC_IP_CACHE="/etc/ax-public-ip"
PUBLIC_IP_TTL=86400 # 缓存有效期 24 小时

# -----------------------------------------------------------------------------
# 获取本机公网 IP 地址 (带文件缓存)
# -----------------------------------------------------------------------------
get_public_ip() {
    if [[ -n "$PUBLIC_IP" ]]; then echo "$PUBLIC_IP"; return; fi
    # 尝试从缓存文件读取 (检查 TTL)
    if [[ -f "$PUBLIC_IP_CACHE" ]]; then
        local cache_time=$(head -1 "$PUBLIC_IP_CACHE" 2>/dev/null)
        local now=$(date +%s)
        if [[ -n "$cache_time" && $((now - cache_time)) -lt $PUBLIC_IP_TTL ]]; then
            PUBLIC_IP=$(sed -n '2p' "$PUBLIC_IP_CACHE" 2>/dev/null)
            [[ -n "$PUBLIC_IP" ]] && { echo "$PUBLIC_IP"; return; }
        fi
    fi
    PUBLIC_IP=$(curl -s4m2 $PUBLIC_IP_SERVICE_1 || curl -s4m2 $PUBLIC_IP_SERVICE_2)
    if [[ -z "$PUBLIC_IP" ]]; then PUBLIC_IP="127.0.0.1"; yellow "获取公网 IP 失败，将使用 127.0.0.1 作为备用。" >&2; fi
    # 写入缓存 (timestamp + IP)
    echo "$(date +%s)" > "$PUBLIC_IP_CACHE" && echo "$PUBLIC_IP" >> "$PUBLIC_IP_CACHE"
    echo "$PUBLIC_IP"
}

# -----------------------------------------------------------------------------
# 统一检测与安装系统依赖和核心程序
# -----------------------------------------------------------------------------
# 检查并安装系统依赖
check_and_install_system_deps() {
    local -A dep_map=(
        ["curl"]="curl" ["wget"]="wget" ["tar"]="tar" ["unzip"]="unzip"
        ["jq"]="jq" ["openssl"]="openssl" ["uuidgen"]="uuid-runtime"
        ["nano"]="nano" ["iptables"]="iptables" ["socat"]="socat"
    )
    
    # 检查 dig 命令
    if ! command -v dig &>/dev/null; then
        if command -v apt-get &>/dev/null; then
            dep_map["dig"]="dnsutils"
        elif command -v yum &>/dev/null || command -v dnf &>/dev/null; then
            dep_map["dig"]="bind-utils"
        fi
    fi
    
    local packages_to_install=()
    for cmd in "${!dep_map[@]}"; do
        if ! command -v "$cmd" &>/dev/null; then
            packages_to_install+=("${dep_map[$cmd]}")
        fi
    done
    
    if [ ${#packages_to_install[@]} -eq 0 ]; then
        green "✓ 所有系统依赖组件已就绪"
        return 0
    fi
    
    echo ""
    yellow "开始下载安装 系统依赖组件..."
    for pkg in "${packages_to_install[@]}"; do
        cyan "  » 安装 $pkg"
    done
    echo ""
    
    if (apt-get update && apt-get install -y "${packages_to_install[@]}") >/dev/null 2>&1 || \
       (yum install -y epel-release && yum install -y "${packages_to_install[@]}") >/dev/null 2>&1 || \
       (dnf install -y "${packages_to_install[@]}") >/dev/null 2>&1; then
        green "✓ 系统依赖组件安装完成！"
    else
        red "✗ 部分系统依赖组件安装失败"
        yellow "请手动执行: apt install ${packages_to_install[*]}"
        return 1
    fi
}

# 检查并下载核心程序
check_and_install_core_programs() {
    cpujg  # 初始化 CPU 架构变量 (供 download 函数使用)
    local need_download=false
    local kcp_ok=true; [[ ! -f "$KCP_INSTALL_DIR/kcptun_server" ]] && { kcp_ok=false; need_download=true; }
    local udp_ok=true; [[ ! -f "$UDP2RAW_INSTALL_DIR/udp2raw" ]] && { udp_ok=false; need_download=true; }
    local singbox_ok=true; [[ ! -f "$SINGBOX_INSTALL_DIR/sing-box" ]] && { singbox_ok=false; need_download=true; }
    
    if [[ "$need_download" == false ]]; then
        green "✓ 所有核心程序已就绪"
        return 0
    fi
    
    echo ""
    yellow "开始下载安装 核心程序..."
    
    if [[ "$kcp_ok" == false || "$udp_ok" == false ]]; then
        cyan "  » 下载 KCPTUN/UDP2RAW"
        download_kcp_udp_binaries || { red "✗ KCPTUN/UDP2RAW 下载失败"; return 1; }
        green "    ✓ KCPTUN/UDP2RAW 安装完成"
    fi
    
    if [[ "$singbox_ok" == false ]]; then
        cyan "  » 下载 Sing-box"
        download_singbox_binary || { red "✗ Sing-box 下载失败"; return 1; }
        green "    ✓ Sing-box 安装完成"
    fi
    
    green "✓ 所有组件安装完成！"
}

# 检查并下载辅助脚本
check_and_install_helper_scripts() {
    AX_ACME_SCRIPT=$(basename "$AX_ACME_URL")
    AX_OPTZ_SCRIPT=$(basename "$AX_OPTZ_URL")
    
    local script_download_needed=false
    [[ ! -f "$AX_ACME_SCRIPT" ]] && script_download_needed=true
    [[ ! -f "$AX_OPTZ_SCRIPT" ]] && script_download_needed=true
    
    if [[ "$script_download_needed" == false ]]; then
        green "✓ 所有辅助脚本已就绪"
        return 0
    fi
    
    echo ""
    yellow "检查辅助脚本..."
    
    if [[ ! -f "$AX_ACME_SCRIPT" ]]; then
        cyan "  » 下载 $AX_ACME_SCRIPT"
        download_with_retry "$AX_ACME_URL" "$AX_ACME_SCRIPT" >/dev/null 2>&1 && chmod +x "$AX_ACME_SCRIPT" && green "    ✓ $AX_ACME_SCRIPT 下载完成" || yellow "    ⚠ $AX_ACME_SCRIPT 下载失败"
    fi
    
    if [[ ! -f "$AX_OPTZ_SCRIPT" ]]; then
        cyan "  » 下载 $AX_OPTZ_SCRIPT"
        download_with_retry "$AX_OPTZ_URL" "$AX_OPTZ_SCRIPT" >/dev/null 2>&1 && chmod +x "$AX_OPTZ_SCRIPT" && green "    ✓ $AX_OPTZ_SCRIPT 下载完成" || yellow "    ⚠ $AX_OPTZ_SCRIPT 下载失败"
    fi
    
    green "✓ 辅助脚本检查完成！"
}

install_dependencies_and_programs(){
    echo ""
    log "正在检测 系统依赖组件与核心程序..."
    echo ""
    
    check_and_install_system_deps || return 1
    echo ""
    check_and_install_core_programs || return 1
    echo ""
    check_and_install_helper_scripts
    echo ""
}

# -----------------------------------------------------------------------------
# 带重试机制的文件下载函数
# 参数: $1=URL, $2=输出路径
# -----------------------------------------------------------------------------
download_with_retry(){
    local url=$1 output=$2 retries=3 timeout=15
    for ((i=1; i<=retries; i++)); do
        log "下载 ($i/$retries)：$url" >&2
        curl -L --connect-timeout 5 --max-time $timeout -o "$output" "$url" && return 0
        yellow "下载失败，正在重试..." >&2
    done
    red "下载失败超过 $retries 次，请检查网络。" >&2
    return 1
}

# -----------------------------------------------------------------------------
# uname -m -> kcptun 官方发布包后缀 (amd64 / arm64 / arm / 386 / ...)
# -----------------------------------------------------------------------------
get_kcptun_arch() {
    case "$(uname -m)" in
        x86_64)              echo "amd64" ;;
        aarch64)             echo "arm64" ;;
        armv7l|armv6l|armv7) echo "arm" ;;
        i386|i686)           echo "386" ;;
        mipsel)              echo "mipsle" ;;
        mips64el)            echo "mips64le" ;;
        ppc64le)             echo "ppc64le" ;;
        *) red "暂不支持的 CPU 架构: $(uname -m)"; return 1 ;;
    esac
}

# -----------------------------------------------------------------------------
# 校验文件是否为合法 ELF 可执行 (4 字节 magic = 0x7f 'E' 'L' 'F')
# 用来拒绝 GitHub raw 404 的 HTML 错误页或下载不完整的垃圾
# -----------------------------------------------------------------------------
is_elf_binary() {
    local f=$1
    [[ -f "$f" ]] || return 1
    head -c 4 "$f" | grep -q $'\x7fELF'
}

# -----------------------------------------------------------------------------
# 确保辅助脚本存在（统一下载函数）
# 参数: $1=脚本名称变量 (如: "$AX_ACME_SCRIPT")
# 参数: $2=脚本 URL
# 参数: $3=强制更新 (true/false, 默认 false)
# -----------------------------------------------------------------------------
ensure_ax_script() {
    local script_name=$1
    local script_url=$2
    local force_update=${3:-false}
    
    # 如果本地存在且不强制更新，直接返回
    if [ -f "$script_name" ] && [ "$force_update" != "true" ]; then
        return 0
    fi
    
    # 否则下载
    log "正在下载最新版本的 ${script_name}..." >&2
    download_with_retry "$script_url" "$script_name" >&2
    if [ $? -ne 0 ]; then
        red "${script_name} 下载失败。" >&2
        return 1
    fi
    chmod +x "$script_name"
    green "${script_name} 下载完成。" >&2
    return 0
}

# -----------------------------------------------------------------------------
# 跨平台哈希函数 (优先 md5sum, 回退 BSD md5 -q)
# 参数: $1=输入字符串
# -----------------------------------------------------------------------------
hash_string() {
    if command -v md5sum >/dev/null 2>&1; then
        printf '%s' "$1" | md5sum 2>/dev/null | awk '{print $1}'
    elif command -v md5 >/dev/null 2>&1; then
        printf '%s' "$1" | md5 -q 2>/dev/null
    fi
}
hash_file() {
    if command -v md5sum >/dev/null 2>&1; then
        md5sum "$1" 2>/dev/null | awk '{print $1}'
    elif command -v md5 >/dev/null 2>&1; then
        md5 -q "$1" 2>/dev/null
    fi
}

# -----------------------------------------------------------------------------
# JSON 字符串值转义: 仅转义 " 和 \ (JSON 字符串中必须转义的两个字符)
# 参数: $1=原始字符串, 输出到 stdout
# -----------------------------------------------------------------------------
json_escape() {
    printf '%s' "$1" | sed 's/["\]/\\&/g'
}

# -----------------------------------------------------------------------------
# 查找一个未被占用的随机端口 (范围: RANDOM_PORT_MIN - RANDOM_PORT_MAX)
# 补充: 设置最大重试次数, 避免在极端情况下死循环
# 修复: 原正则 [^0-9:] 排除了冒号, 导致 0.0.0.0:PORT 无法匹配
# -----------------------------------------------------------------------------
find_available_port() {
    local port max_attempts=50
    for ((i=0; i<max_attempts; i++)); do
        port=$(( RANDOM_PORT_MIN + RANDOM % (RANDOM_PORT_MAX - RANDOM_PORT_MIN) ))
        # 检查端口是否被占用 (不依赖 ss, 避免不同版本输出格式差异)
        if ! command -v ss &>/dev/null; then
            echo "$port"; return
        fi
        # ss -tuln 输出格式: *:PORT / [::]:PORT / 0.0.0.0:PORT 等
        # 匹配 :PORT 后紧跟空格或行尾, 避免部分匹配 (如 80 匹配 8080)
        if ! ss -tuln 2>/dev/null | grep -qE ":${port}([[:space:]]|\$)"; then
            echo "$port"; return
        fi
    done
    red "错误: 在 $max_attempts 次重试内未找到可用端口" >&2
    return 1
}

# -----------------------------------------------------------------------------
# 生成强密码 (优先使用 uuidgen，失败则使用 hexdump)
# -----------------------------------------------------------------------------
generate_strong_password() {
    if command -v uuidgen >/dev/null 2>&1; then
        uuidgen
    else
        log "uuidgen 未找到，生成备用 UUID..." >&2
        hexdump -n 16 -v -e '4/4 "%08x" "-" 2/2 "%04x" "-" 2/2 "%04x" "-" 2/2 "%04x" "-" 6/6 "%012x"' /dev/urandom | head -c 36
    fi
}

# -----------------------------------------------------------------------------
# 生成自签名证书 (用于 Sing-box Hysteria2 入站 TLS)
# -----------------------------------------------------------------------------
generate_self_signed_cert() {
    if [[ -s "$HY2_CERT_PATH" && -s "$HY2_KEY_PATH" ]]; then return; fi
    log "正在为 ${HY2_SNI} 生成自签名证书..."
    mkdir -p "$(dirname "$HY2_KEY_PATH")"
    # 生成私钥
    openssl ecparam -name prime256v1 -genkey -noout -out "$HY2_KEY_PATH"
    chmod 600 "$HY2_KEY_PATH"
    if [[ $? -ne 0 ]]; then red "错误: openssl ecparam 命令执行失败。"; exit 1; fi
    # 生成证书
    openssl req -new -x509 -days 36500 -key "$HY2_KEY_PATH" -out "$HY2_CERT_PATH" -subj "/CN=${HY2_SNI}" -nodes
    if [[ $? -ne 0 ]]; then red "错误: openssl req 命令执行失败。"; exit 1; fi
    if [[ ! -s "$HY2_CERT_PATH" || ! -s "$HY2_KEY_PATH" ]]; then red "错误: 证书文件生成失败或为空！"; exit 1; fi
    green "证书生成完毕。"
}

# -----------------------------------------------------------------------------
# 处理密码输入逻辑
# 支持自动生成、手动输入和保存上次使用的密码
# -----------------------------------------------------------------------------
handle_password_input() {
    local service_type=$1; local pass_file; local last_pass=""
    # 根据服务类型确定密码保存文件路径
    case "$service_type" in
        kcptun) mkdir -p "$KCP_INSTALL_DIR"; pass_file="$KCP_INSTALL_DIR/last_${service_type}_pass.txt" ;;
        udp2raw) mkdir -p "$UDP2RAW_INSTALL_DIR"; pass_file="$UDP2RAW_INSTALL_DIR/last_${service_type}_pass.txt" ;;
        shadowsocks) mkdir -p "$SINGBOX_INSTALL_DIR"; pass_file="$SINGBOX_INSTALL_DIR/last_ss_pass.txt" ;;
        hysteria2) mkdir -p "$SINGBOX_INSTALL_DIR"; pass_file="$SINGBOX_INSTALL_DIR/last_hy2_pass.txt" ;;
    esac
    
    # 读取上次保存的密码 (如果存在)
    if [[ -f "$pass_file" ]]; then last_pass=$(cat "$pass_file"); fi
    local display_pass=${last_pass:-"无"}
    local prompt_text="请输入密码"

    # 为 SS-2022 提供特定提示
    if [[ "$service_type" == "shadowsocks" ]]; then
         yellow "注意: SS-2022 (如 $SS_DEFAULT_METHOD) 必须使用 Base64 密钥。" >&2
         prompt_text="请输入 Base64 密钥"
    fi

    read -p "${prompt_text} (原有: ${display_pass}, 回车自动生成): " password

    if [[ -z "$password" ]]; then
        # 用户未输入，使用自动生成逻辑
        if [[ "$service_type" == "shadowsocks" ]]; then
            # SS-2022 需要特定长度的 Base64 密钥
            local key_length=32 # 默认 32 字节 (用于 256-gcm)
            if [[ "$SS_DEFAULT_METHOD" == *"128-gcm"* ]]; then
                key_length=16 # 16 字节 (用于 128-gcm)
            fi
            
            if ! command -v openssl &>/dev/null; then
                red "错误: openssl 命令未找到，无法生成 SS-2022 密钥！" >&2
                return 1
            fi
            password=$(openssl rand -base64 $key_length)
            green "已为您自动生成 SS-2022 Base64 密钥: $password" >&2
        else
            # 其他服务使用通用强密码生成
            password=$(generate_strong_password)
            green "已为您自动生成随机密码: $password" >&2
        fi
    else
        # 用户手动输入了密码
        if [[ "$service_type" == "shadowsocks" ]]; then
            yellow "警告: 已使用您输入的 '$password'。" >&2
            yellow "如果 Shadowsocks 启动失败，请检查这是否是有效的 Base64 密钥。" >&2
        fi
    fi

    # 保存密码到文件并设置权限
    echo "$password" > "$pass_file"
    chmod 600 "$pass_file"
    echo "$password"
}

# =============================================================================
# 11. 参数收集公共函数 (交互式)
# =============================================================================

# -----------------------------------------------------------------------------
# 收集 UDP2RAW 参数
# 返回格式: raw_mode|cipher_mode|auth_mode
# -----------------------------------------------------------------------------
collect_udp2raw_params() {
    # raw_mode 白名单校验
    while true; do
        read -p "raw_mode [faketcp/udp/icmp] (默认 faketcp): " raw_mode >&2
        raw_mode=${raw_mode:-faketcp}
        [[ "$raw_mode" =~ ^(faketcp|udp|icmp)$ ]] && break
        red "raw_mode 必须是 faketcp/udp/icmp 之一！" >&2
    done

    # cipher_mode 白名单校验
    while true; do
        read -p "cipher_mode [aes128cbc/xor/none] (默认 aes128cbc): " cipher_mode >&2
        cipher_mode=${cipher_mode:-aes128cbc}
        [[ "$cipher_mode" =~ ^(aes128cbc|xor|none)$ ]] && break
        red "cipher_mode 必须是 aes128cbc/xor/none 之一！" >&2
    done

    # auth_mode 白名单校验
    while true; do
        read -p "auth_mode [hmac_sha1/simple/md5] (默认 hmac_sha1): " auth_mode >&2
        auth_mode=${auth_mode:-hmac_sha1}
        [[ "$auth_mode" =~ ^(hmac_sha1|simple|md5)$ ]] && break
        red "auth_mode 必须是 hmac_sha1/simple/md5 之一！" >&2
    done

    echo "$raw_mode|$cipher_mode|$auth_mode"
}

# -----------------------------------------------------------------------------
# 收集 KCPTUN 参数
# 返回格式: mode|crypt|tcp_enabled|mtu|sndwnd|rcvwnd
# -----------------------------------------------------------------------------
# 内部: 校验数值范围 (mtu: 200-1500, sndwnd/rcvwnd: 16-65535)
_validate_num_range() {
    local val=$1 min=$2 max=$3 name=$4
    if ! [[ "$val" =~ ^[0-9]+$ ]] || (( val < min || val > max )); then
        red "$name 必须是 $min-$max 之间的数字！" >&2
        return 1
    fi
}

collect_kcptun_params() {
    # MTU 校验 (200-1500, RFC 推荐 1200)
    while true; do
        read -p "MTU (默认 1200, 范围 200-1500): " mtu >&2
        mtu=${mtu:-1200}
        _validate_num_range "$mtu" 200 1500 "MTU" && break
    done

    # sndwnd 校验 (16-65535)
    while true; do
        read -p "sndwnd (默认 2048, 范围 16-65535): " sndwnd >&2
        sndwnd=${sndwnd:-2048}
        _validate_num_range "$sndwnd" 16 65535 "sndwnd" && break
    done

    # rcvwnd 校验 (16-65535)
    while true; do
        read -p "rcvwnd (默认 2048, 范围 16-65535): " rcvwnd >&2
        rcvwnd=${rcvwnd:-2048}
        _validate_num_range "$rcvwnd" 16 65535 "rcvwnd" && break
    done

    # mode 白名单
    while true; do
        read -p "mode [fast/fast2/fast3/normal/manual] (默认 $KCPTUN_DEFAULT_MODE): " mode >&2
        mode=${mode:-$KCPTUN_DEFAULT_MODE}
        [[ "$mode" =~ ^(fast|fast2|fast3|normal|manual)$ ]] && break
        red "mode 必须是 fast/fast2/fast3/normal/manual 之一！" >&2
    done

    # crypt 白名单
    while true; do
        read -p "crypt [aes-128/aes-192/aes-256] (默认 aes-128): " crypt >&2
        crypt=${crypt:-aes-128}
        [[ "$crypt" =~ ^(aes-128|aes-192|aes-256)$ ]] && break
        red "crypt 必须是 aes-128/aes-192/aes-256 之一！" >&2
    done

    # tcp_enabled 白名单
    while true; do
        read -p "tcp [true/false] (默认 false): " tcp_enabled >&2
        tcp_enabled=${tcp_enabled:-false}
        [[ "$tcp_enabled" =~ ^(true|false)$ ]] && break
        red "tcp 必须是 true/false 之一！" >&2
    done

    echo "$mode|$crypt|$tcp_enabled|$mtu|$sndwnd|$rcvwnd"
}


# -----------------------------------------------------------------------------
# WARP WireGuard 注册 (通过 Cloudflare API 自动获取密钥对与地址)
# 输出: 将 WARP 密钥写入 $SINGBOX_INSTALL_DIR/.warp_wireguard.json
# -----------------------------------------------------------------------------
register_warp_wireguard() {
    local warp_key_file="$SINGBOX_INSTALL_DIR/.warp_wireguard.json"
    mkdir -p "$SINGBOX_INSTALL_DIR"
    
    # 生成 WireGuard 密钥对 (使用 sing-box 内置功能，无需 wireguard-tools)
    local wg_private wg_public
    if command -v wg &>/dev/null; then
        wg_private=$(wg genkey)
        wg_public=$(echo "$wg_private" | wg pubkey)
    elif [[ -f "$SINGBOX_INSTALL_DIR/sing-box" ]]; then
        local wg_keypair=$("$SINGBOX_INSTALL_DIR/sing-box" generate wg-keypair 2>/dev/null)
        wg_private=$(echo "$wg_keypair" | grep "PrivateKey" | awk '{print $2}')
        wg_public=$(echo "$wg_keypair" | grep "PublicKey" | awk '{print $2}')
        if [[ -z "$wg_private" || -z "$wg_public" ]]; then
            red "错误: sing-box 密钥生成失败。"; return 1
        fi
    else
        red "错误: 无可用的 WireGuard 密钥生成工具。请安装 wireguard-tools 或 sing-box。"
        return 1
    fi
    
    # 调用 Cloudflare WARP API 注册
    local api_result=$(curl -s --connect-timeout 10 \
        "https://api.cloudflareclient.com/v0a$(printf '%04d' $((RANDOM % 10000)))/reg" \
        -H "Content-Type: application/json" \
        -d "{\"key\": \"${wg_public}\", \"install_id\": \"\", \"fcm_token\": \"\", \"warp_enabled\": false, \"locale\": \"zh_CN\"}")
    
    local client_id=$(echo "$api_result" | jq -r '.id // empty' 2>/dev/null)
    local wg_private_key=$(echo "$api_result" | jq -r '.config.interface.private_key // empty' 2>/dev/null)
    local wg_address_v4=$(echo "$api_result" | jq -r '.config.interface.addresses.v4 // empty' 2>/dev/null)
    if [[ -z "$wg_address_v4" || "$wg_address_v4" == "null" ]]; then
        wg_address_v4="172.16.0.2"
    fi
    local wg_address_v6=$(echo "$api_result" | jq -r '.config.interface.addresses.v6 // empty' 2>/dev/null)
    
    # 若 API 返回了服务端分配的私钥则使用之，否则用本地生成的
    if [[ -z "$wg_private_key" || "$wg_private_key" == "null" ]]; then
        wg_private_key="$wg_private"
    fi
    
    # 提取 IPv6 后缀 (最后 4 段)
    local ipv6_suffix=""
    if [[ -n "$wg_address_v6" && "$wg_address_v6" != "null" ]]; then
        ipv6_suffix=$(echo "$wg_address_v6" | sed 's|/128||' | awk -F: '{print $5":"$6":"$7":"$8}')
    fi
    if [[ -z "$ipv6_suffix" ]]; then
        # 回退: 从客户端地址派生
        local client_hash=$(hash_string "$client_id" | head -c 8 | sed 's/\(....\)\(....\)/\1:\2/')
        ipv6_suffix="100:${client_hash}"
        [[ ${#ipv6_suffix} -lt 10 ]] && ipv6_suffix="100:$(printf '%x' $RANDOM):$(printf '%x' $RANDOM):$(printf '%x' $RANDOM)"
    fi
    
    # 写入密钥文件
    cat > "$warp_key_file" <<EOF
{
    "private_key": "$wg_private_key",
    "address_v4": "$wg_address_v4/32",
    "address_v6": "2606:4700:110:${ipv6_suffix}/128",
    "reserved": [0, 0, 0]
}
EOF
    chmod 600 "$warp_key_file"
    green "✓ WARP WireGuard 注册成功！密钥已保存至 $warp_key_file"
    green "  Private key: $wg_private_key"
    green "  IPv4: $wg_address_v4/32"
    green "  IPv6: 2606:4700:110:${ipv6_suffix}/128"
    
}

# -----------------------------------------------------------------------------
# 从密钥文件加载 WARP WireGuard 配置到模板
# -----------------------------------------------------------------------------
apply_warp_wireguard_config() {
    local warp_key_file="$SINGBOX_INSTALL_DIR/.warp_wireguard.json"
    if [[ ! -f "$warp_key_file" ]]; then
        red "错误: WARP WireGuard 密钥文件不存在。请先执行 register_warp_wireguard。" >&2
        return 1
    fi
    if ! command -v jq &>/dev/null; then
        red "错误: jq 未安装, 无法解析 WARP 密钥文件。" >&2
        return 1
    fi
    local block=$SINGBOX_WARP_WIREGUARD_ENDPOINT
    local addr=$(jq -r '.address_v4 // "172.16.0.2/32"' "$warp_key_file" 2>/dev/null)
    if [[ -z "$addr" || "$addr" == "null" || "$addr" == "/32" ]]; then
        addr="172.16.0.2/32"
        yellow "警告: WARP IPv4 地址缺失, 使用默认 172.16.0.2/32。" >&2
    fi
    local priv_key=$(jq -r '.private_key // empty' "$warp_key_file" 2>/dev/null)
    if [[ -z "$priv_key" || "$priv_key" == "null" ]]; then
        red "错误: WARP 私钥为空，无法生成 endpoint。" >&2
        return 1
    fi
    block=${block/__WARP_ADDRESS__/$addr}
    block=${block/__WARP_PRIVATE_KEY__/$priv_key}
    echo "$block"
}

# -----------------------------------------------------------------------------
# 在 singbox.json 中添加 WARP endpoint + 路由规则 + mixed-in (首次启用)
# 已启用时跳过 (幂等)
# -----------------------------------------------------------------------------
enable_warp_in_config() {
    local config_file="$SINGBOX_INSTALL_DIR/singbox.json"
    if [[ ! -f "$config_file" ]]; then red "错误: singbox.json 不存在。" >&2; return 1; fi
    if ! command -v python3 &>/dev/null; then red "错误: python3 未安装。" >&2; return 1; fi
    if python3 -c "
import json,sys
cfg = json.load(open('$config_file'))
for ep in cfg.get('endpoints', []):
    if ep.get('tag') == 'warp-ep' and ep.get('type') == 'wireguard':
        sys.exit(0)
sys.exit(1)
" 2>/dev/null; then
        green "WARP 已在配置中启用，无需重复操作。"; return 0
    fi
    local warp_key_file="$SINGBOX_INSTALL_DIR/.warp_wireguard.json"
    if [[ ! -f "$warp_key_file" ]]; then
        red "错误: WARP 密钥文件不存在，请先注册 WARP。" >&2; return 1
    fi
    local wg_ep; wg_ep=$(apply_warp_wireguard_config) || return 1
    local route_rules=$SINGBOX_DIRECT_ROUTE_RULES
    route_rules=${route_rules//__WARP_DOMAIN_SUFFIX_LIST__/$(get_warp_domain_list)}
    local tmpfile; tmpfile=$(umask 077 && mktemp) || { red "无法创建临时文件" >&2; return 1; }
    local ep_tmp; ep_tmp=$(umask 077 && mktemp) || { red "无法创建临时文件" >&2; rm -f "$tmpfile"; return 1; }
    local rules_tmp; rules_tmp=$(umask 077 && mktemp) || { red "无法创建临时文件" >&2; rm -f "$tmpfile" "$ep_tmp"; return 1; }
    printf '%s\n' "$wg_ep" > "$ep_tmp"
    printf '%s\n' "$route_rules" > "$rules_tmp"
    if ! python3 -c "
import json,sys
cfg = json.load(open('$config_file'))
endpoints = json.load(open('$ep_tmp'))
rules = json.load(open('$rules_tmp'))
cfg['endpoints'] = endpoints
cfg['route']['rules'] = rules
# 添加 mixed inbound 用于本地通过 sing-box 路由查询 WARP 出口 IP
mixed_in = {'type': 'mixed', 'tag': 'mixed-in', 'listen': '127.0.0.1', 'listen_port': 17888}
if not any(i.get('tag') == 'mixed-in' for i in cfg.get('inbounds', [])):
    cfg.setdefault('inbounds', []).append(mixed_in)
json.dump(cfg, open('$tmpfile','w'), indent=2)
" 2>/dev/null; then
        rm -f "$tmpfile" "$ep_tmp" "$rules_tmp"; red "合并失败。" >&2; return 1
    fi
    rm -f "$ep_tmp" "$rules_tmp"
    if ! python3 -c "import json; json.load(open('$tmpfile'))" 2>/dev/null; then
        rm -f "$tmpfile"; red "输出 JSON 不合法。" >&2; return 1
    fi
    mv "$tmpfile" "$config_file"
    green "✓ WARP 已启用"
}

# -----------------------------------------------------------------------------
# 从 singbox.json 中移除 WARP endpoint + 路由规则 + mixed-in (完全禁用)
# 未启用时跳过 (幂等)
# -----------------------------------------------------------------------------
disable_warp_in_config() {
    local config_file="$SINGBOX_INSTALL_DIR/singbox.json"
    if [[ ! -f "$config_file" ]]; then red "错误: singbox.json 不存在。" >&2; return 1; fi
    if ! command -v python3 &>/dev/null; then red "错误: python3 未安装。" >&2; return 1; fi
    if ! python3 -c "
import json,sys
cfg = json.load(open('$config_file'))
for ep in cfg.get('endpoints', []):
    if ep.get('tag') == 'warp-ep' and ep.get('type') == 'wireguard':
        sys.exit(0)
sys.exit(1)
" 2>/dev/null; then
        yellow "WARP 未启用，无需操作。"; return 0
    fi
    local tmpfile; tmpfile=$(umask 077 && mktemp) || { red "无法创建临时文件" >&2; return 1; }
    if ! python3 -c "
import json
cfg = json.load(open('$config_file'))
cfg['endpoints'] = []
cfg['route']['rules'] = []
cfg['inbounds'] = [i for i in cfg.get('inbounds', []) if i.get('tag') != 'mixed-in']
json.dump(cfg, open('$tmpfile','w'), indent=2)
" 2>/dev/null; then
        rm -f "$tmpfile"; red "移除失败。" >&2; return 1
    fi
    mv "$tmpfile" "$config_file"
    green "✓ WARP 已禁用"
}

# -----------------------------------------------------------------------------
# 更新 singbox.json 中的 WARP 分流域名 (仅替换 route.rules，不动 endpoint/inbound)
# 前置条件: WARP 已启用 (存在 warp-ep endpoint)
# 返回值: 0=成功, 1=WARP未启用/失败
# -----------------------------------------------------------------------------
update_warp_domains() {
    local config_file="$SINGBOX_INSTALL_DIR/singbox.json"
    if [[ ! -f "$config_file" ]]; then red "错误: singbox.json 不存在。" >&2; return 1; fi
    if ! command -v python3 &>/dev/null; then red "错误: python3 未安装。" >&2; return 1; fi
    if ! python3 -c "
import json,sys
cfg = json.load(open('$config_file'))
for ep in cfg.get('endpoints', []):
    if ep.get('tag') == 'warp-ep' and ep.get('type') == 'wireguard':
        sys.exit(0)
sys.exit(1)
" 2>/dev/null; then
        yellow "WARP 未启用，无需更新。"; return 1
    fi
    local route_rules=$SINGBOX_DIRECT_ROUTE_RULES
    route_rules=${route_rules//__WARP_DOMAIN_SUFFIX_LIST__/$(get_warp_domain_list)}
    local tmpfile; tmpfile=$(umask 077 && mktemp) || { red "无法创建临时文件" >&2; return 1; }
    local rules_tmp; rules_tmp=$(umask 077 && mktemp) || { red "无法创建临时文件" >&2; rm -f "$tmpfile"; return 1; }
    printf '%s\n' "$route_rules" > "$rules_tmp"
    if ! python3 -c "
import json
cfg = json.load(open('$config_file'))
rules = json.load(open('$rules_tmp'))
cfg['route']['rules'] = rules
json.dump(cfg, open('$tmpfile','w'), indent=2)
" 2>/dev/null; then
        rm -f "$tmpfile" "$rules_tmp"; red "更新失败。" >&2; return 1
    fi
    rm -f "$rules_tmp"
    if ! python3 -c "import json; json.load(open('$tmpfile'))" 2>/dev/null; then
        rm -f "$tmpfile"; red "输出 JSON 不合法。" >&2; return 1
    fi
    mv "$tmpfile" "$config_file"
    green "✓ WARP 分流域名已更新"
}

# -----------------------------------------------------------------------------
# 读取 .warp_domain_list → 输出 JSON 数组字符串 ("a","b","c",...)
# 文件不存在时自动创建 (含默认分流域名)
# 忽略 # 注释行、空行、空白字符
# -----------------------------------------------------------------------------
get_warp_domain_list() {
    local domain_file="$SINGBOX_INSTALL_DIR/.warp_domain_list"
    if [[ ! -f "$domain_file" ]]; then
        cat > "$domain_file" <<'EOF'
openai.com
chatgpt.com
chat.com
oaiusercontent.com
perplexity.ai
google.com
googleapis.com
grok.com
x.ai
claude.ai
anthropic.com
x.com
twitter.com
facebook.com
instagram.com
threads.net
youtube.com
ytimg.com
googlevideo.com
telegram.org
t.me
discord.com
discordapp.net
reddit.com
redditmedia.com
wikipedia.org
medium.com
quora.com
stackoverflow.com
sourceforge.net
ip.skk.moe
ip-api.com
EOF
    fi
    local first=true
    while IFS= read -r line; do
        line="${line%%#*}"
        line="${line//[[:space:]]/}"
        [[ -z "$line" ]] && continue
        if $first; then
            echo -n "\"${line}\""
            first=false
        else
            echo -n ",\"${line}\""
        fi
    done < "$domain_file"
    echo
}

# -----------------------------------------------------------------------------
# 编辑 WARP 分流域名列表 (nano)
# 流程: 规范化 → 记哈希 → nano → 再规范化 → 比较哈希
# 有变化 → update_warp_domains + 重启 sing-box
# 无变化 → 不动
# -----------------------------------------------------------------------------
edit_warp_domains() {
    local domain_file="$SINGBOX_INSTALL_DIR/.warp_domain_list"
    [[ -f "$domain_file" ]] || get_warp_domain_list > /dev/null
    # 先规范化一次：去注释/空格/空行，去重排序
    local tmpfile; tmpfile=$(umask 077 && mktemp) || { red "无法创建临时文件" >&2; return 1; }
    awk '{ sub(/[[:space:]]*#.*$/,""); gsub(/[[:space:]]/,""); if ($0!="") print tolower($0) }' "$domain_file" | sort -u > "$tmpfile"
    if [[ -s "$tmpfile" ]]; then
        mv "$tmpfile" "$domain_file"
    else
        rm -f "$tmpfile"; red "域名列表为空！" >&2; return 1
    fi
    local before_hash; before_hash=$(hash_file "$domain_file")
    nano "$domain_file"
    # 编辑后再规范化 (使用不同变量名, 避免与前面已清理的 tmpfile 混淆)
    local normfile; normfile=$(umask 077 && mktemp) || { red "无法创建临时文件" >&2; return 1; }
    awk '{ sub(/[[:space:]]*#.*$/,""); gsub(/[[:space:]]/,""); if ($0!="") print tolower($0) }' "$domain_file" | sort -u > "$normfile"
    if [[ -s "$normfile" ]]; then
        mv "$normfile" "$domain_file"
    else
        rm -f "$normfile"; red "域名列表为空！" >&2; return 1
    fi
    local after_hash; after_hash=$(hash_file "$domain_file")
    if [[ "$before_hash" != "$after_hash" ]]; then
        local count; count=$(wc -l < "$domain_file")
        green "域名已更新: $count 个"
        yellow "正在更新配置并重启..."
        if update_warp_domains; then
            sync
            systemctl restart ax-singbox.service 2>/dev/null
            green "Sing-box 已重启，新域名已生效。"
        else
            yellow "域名已保存，但未能更新配置。请稍后手动重启。"
        fi
    else
        yellow "域名列表无变化，无需重启。"
    fi
}

# -----------------------------------------------------------------------------
# WARP 管理子菜单
# 根据 WARP 启用/密钥状态动态显示: 启用/禁用 + 编辑分流域名
# 启用时显示出口 IP (通过 mixed-in SOCKS5 查询)
# -----------------------------------------------------------------------------
warp_management_menu() {
    local warp_key_file="$SINGBOX_INSTALL_DIR/.warp_wireguard.json"
    while true; do
        local cfg_enabled=false
        if jq -e '.endpoints[] | select(.tag == "warp-ep" and .type == "wireguard")' "$SINGBOX_INSTALL_DIR/singbox.json" >/dev/null 2>&1; then
            cfg_enabled=true
        fi

        echo "=================================="
        echo "       WARP分流管理"
        echo "=================================="
        if $cfg_enabled; then
            green "当前状态: 已启用"
            local warp_ip=$(curl -s --max-time 3 --socks5-hostname 127.0.0.1:17888 http://ip-api.com/json/ 2>/dev/null | jq -r '.query // empty')
            [[ -n "$warp_ip" ]] && echo "      出口IP: $warp_ip"
            echo "----------------------------------"
            echo " 1) 禁用 WARP 分流"
            echo " 2) 编辑 WARP 分流域名"
        elif [[ -f "$warp_key_file" ]]; then
            yellow "当前状态: 未启用"
            echo "----------------------------------"
            echo " 1) 启用 WARP 分流"
            echo " 2) 编辑 WARP 分流域名"
        else
            yellow "当前状态: 未启用"
            echo "----------------------------------"
            echo " 1) 启用 WARP 分流"
            echo " 2) 编辑 WARP 分流域名"
        fi
        echo " 0) 返回"
        read -p "请选择: " warp_choice

        if $cfg_enabled; then
            case $warp_choice in
                1) if disable_warp_in_config; then sync; systemctl restart ax-singbox.service 2>/dev/null; green "Sing-box 已重启。"; else yellow "禁用失败。"; fi; read -p $'\n按任意键返回主菜单...' -n1 -s; break;;
2) edit_warp_domains;;
0) break;;
                *) red "无效选择!"; sleep 1;;
            esac
        elif [[ -f "$warp_key_file" ]]; then
            case $warp_choice in
                1) if enable_warp_in_config; then sync; systemctl restart ax-singbox.service 2>/dev/null; green "Sing-box 已重启。"; else yellow "启用失败。"; fi; read -p $'\n按任意键返回主菜单...' -n1 -s; break;;
2) edit_warp_domains;;
0) break;;
                *) red "无效选择!"; sleep 1;;
            esac
        else
            case $warp_choice in
                1)
                    if register_warp_wireguard; then
                        enable_warp_in_config && { sync; systemctl restart ax-singbox.service 2>/dev/null; green "WARP 已启用！"; } || yellow "启用失败。"
                    else
                        yellow "注册失败。"
                    fi
                    read -p $'\n按任意键返回主菜单...' -n1 -s; break;;
2) edit_warp_domains;;
0) break;;
                *) red "无效选择!"; sleep 1;;
            esac
        fi
    done
}

# -----------------------------------------------------------------------------
# 读取并校验端口 (1024-65535)
# 参数: $1=提示文字, $2=变量名, $3=是否随机生成 (true/false)
# -----------------------------------------------------------------------------
read_valid_port() {
    local prompt=$1 var_name=$2 allow_random=$3
    while true; do
        read -p "$prompt" input
        if [[ -z "$input" && "$allow_random" == "true" ]]; then
            input=$(find_available_port)
            green "已为您随机选择端口: $input" >&2
            eval "$var_name='$input'"; return
        fi
        if [[ "$input" =~ ^[0-9]+$ ]] && (( input >= 1024 && input <= 65535 )); then
            eval "$var_name='$input'"; return
        fi
        red "端口必须是 1024-65535 之间的数字！" >&2
    done
}

# -----------------------------------------------------------------------------
# 查找下一个可用的实例 ID (数字)
# 遍历目录查找未使用的文件名编号
# -----------------------------------------------------------------------------
find_next_available_id() {
    local type=$1; local dir file_prefix file_ext; local i=1
    case "$type" in
        udp2raw) dir="$UDP2RAW_INSTALL_DIR"; file_prefix="udp2raw"; file_ext="conf";;
        kcptun) dir="$KCP_INSTALL_DIR"; file_prefix="kcptun"; file_ext="json";;
        singbox)
            local config_file="$SINGBOX_INSTALL_DIR/singbox.json"
            if [[ -f "$config_file" ]]; then
                local used_ids=$(jq -r '.inbounds[].tag | capture("(?<pre>vless-reality-|ss-|hy2-)(?<id>[0-9]+)") | .id' "$config_file" 2>/dev/null | sort -n)
                while true; do
                    if ! echo "$used_ids" | grep -q "^${i}$"; then echo "$i"; return; fi
                    i=$((i + 1))
                done
            else
                echo "1"; return
            fi
            ;;
    esac
    while true; do
        if [[ ! -f "$dir/${file_prefix}_${i}.${file_ext}" && ! -f "$dir/${file_prefix}_c${i}.${file_ext}" && ! -f "$dir/${file_prefix}_vc${i}.${file_ext}" && ! -f "$dir/${file_prefix}_s3c${i}.${file_ext}" ]]; then
            echo "$i"; return
        fi
        i=$((i + 1))
    done
}

# =============================================================================
# 13. 核心程序下载与安装函数
# =============================================================================

# -----------------------------------------------------------------------------
# 获取 GitHub 仓库最新 Release 标签
# -----------------------------------------------------------------------------
get_latest_github_tag() {
    local repo_name=$1
    curl -sIL -o /dev/null -w '%{url_effective}' "$GITHUB_URL/$repo_name/releases/latest" 2>/dev/null | grep -oE 'tag/[^/]+$' | cut -d/ -f2
}

# -----------------------------------------------------------------------------
# 下载并安装 KCPTUN 和 UDP2RAW 二进制文件
# -----------------------------------------------------------------------------
download_kcp_udp_binaries(){
    mkdir -p "$KCP_INSTALL_DIR"
    mkdir -p "$UDP2RAW_INSTALL_DIR"

    local kcp_current=$(cat "$KCP_INSTALL_DIR/version.txt" 2>/dev/null)
    local udp_current=$(cat "$UDP2RAW_INSTALL_DIR/version.txt" 2>/dev/null)
    local fixed_version_kcp="Fixed-Source-v1.0.2"
    local fixed_version_udp="Fixed-Source-v1.0.2"

    # KCPTUN - 只有版本不匹配或文件缺失才下载
    if [[ "$kcp_current" != "$fixed_version_kcp" || ! -f "$KCP_INSTALL_DIR/kcptun_server" ]]; then
        log "下载 KCPTUN (kcptun_server)..."
        download_with_retry "https://raw.githubusercontent.com/halibotee/scripts/main/package/kcptun_server" "$KCP_INSTALL_DIR/kcptun_server" && \
        chmod +x "$KCP_INSTALL_DIR/kcptun_server" && \
        echo "$fixed_version_kcp" > "$KCP_INSTALL_DIR/version.txt" || { red "KCPTUN 下载失败。"; return 1; }
    else
        green "KCPTUN 已是最新版本 ($kcp_current)"
    fi

    # UDP2RAW - 只有版本不匹配或文件缺失才下载
    if [[ "$udp_current" != "$fixed_version_udp" || ! -f "$UDP2RAW_INSTALL_DIR/udp2raw" ]]; then
        log "下载 UDP2RAW (udp2raw_binaries.tar.gz)..."
        download_with_retry "https://raw.githubusercontent.com/halibotee/scripts/main/package/udp2raw_binaries.tar.gz" /tmp/udp2raw.tar.gz && \
        tar -xzf /tmp/udp2raw.tar.gz -C "$UDP2RAW_INSTALL_DIR" "udp2raw_${cpu}" && \
        mv "$UDP2RAW_INSTALL_DIR/udp2raw_${cpu}" "$UDP2RAW_INSTALL_DIR/udp2raw" && \
        echo "$fixed_version_udp" > "$UDP2RAW_INSTALL_DIR/version.txt" && \
        chmod +x "$UDP2RAW_INSTALL_DIR/udp2raw" || { red "UDP2RAW 下载失败。"; return 1; }
    else
        green "UDP2RAW 已是最新版本 ($udp_current)"
    fi
}

# -----------------------------------------------------------------------------
# 下载并安装 Sing-box 二进制文件
# -----------------------------------------------------------------------------
download_singbox_binary(){
    local singbox_latest=$(get_latest_github_tag "$SINGBOX_REPO")
    if [[ -z "$singbox_latest" ]]; then red "获取 Sing-box 版本号失败。"; return 1; fi
    
    mkdir -p "$SINGBOX_INSTALL_DIR"
    local singbox_current=$(cat "$SINGBOX_INSTALL_DIR/version.txt" 2>/dev/null)
    
    if [[ "$singbox_latest" != "$singbox_current" ]]; then
        log "发现 Sing-box 新版本: $singbox_latest (当前: ${singbox_current:-未知})"
        log "下载 Sing-box ($singbox_latest)..."
        local singbox_ver="${singbox_latest#v}"
        local singbox_url="$GITHUB_URL/$SINGBOX_REPO/releases/download/${singbox_latest}/sing-box-${singbox_ver}-linux-${cpu}.tar.gz"
        download_with_retry "$singbox_url" /tmp/singbox.tar.gz || {
            # fallback: try with v prefix in archive name
            singbox_url="$GITHUB_URL/$SINGBOX_REPO/releases/download/${singbox_latest}/sing-box-${singbox_latest}-linux-${cpu}.tar.gz"
            download_with_retry "$singbox_url" /tmp/singbox.tar.gz || { red "Sing-box 下载失败。"; return 1; }
        }
        tar -xzf /tmp/singbox.tar.gz -C /tmp && \
        cp "/tmp/sing-box-${singbox_ver}-linux-${cpu}/sing-box" "$SINGBOX_INSTALL_DIR/sing-box" && \
        chmod +x "$SINGBOX_INSTALL_DIR/sing-box" && \
        echo "$singbox_latest" > "$SINGBOX_INSTALL_DIR/version.txt" || { red "Sing-box 解压/安装失败。"; return 1; }
        rm -rf "/tmp/sing-box-${singbox_latest}-linux-${cpu}" /tmp/singbox.tar.gz
    else
        green "Sing-box 已是最新版本 ($singbox_latest)"
    fi
}

# =============================================================================
# 14. Systemd 服务管理与状态查询
# =============================================================================

# 更新 systemd 服务模板
update_service_template() {
    local content=$1 template_file=$2
    local hash=$(hash_string "$content")
    local existing_hash=$(hash_file "$template_file")
    
    if [[ "$hash" != "$existing_hash" ]]; then
        echo "$content" > "$template_file"
        return 0  # 需要 reload
    fi
    return 1  # 不需要 reload
}

# 创建初始 Sing-box 配置
create_initial_singbox_config() {
    mkdir -p "$SINGBOX_INSTALL_DIR"
    
    if [[ -f "$SINGBOX_INSTALL_DIR/singbox.json" ]]; then
        return 1  # 已存在，不需要创建
    fi
    
    local base_config=$SINGBOX_BASE_CONFIG_TEMPLATE
    local endpoints_json='[]'
    local route_rules=$SINGBOX_NO_WARP_ROUTE_RULES

    # 自动注册 WARP WireGuard (首次安装时执行)
    if command -v wg &>/dev/null && [[ ! -f "$SINGBOX_INSTALL_DIR/.warp_wireguard.json" ]]; then
        log "首次安装, 正在尝试自动注册 WARP WireGuard..."
        if ! register_warp_wireguard; then
            yellow "警告: WARP 自动注册失败, 将创建不带 WARP 的默认配置。可稍后手动重新注册。"
        fi
    fi
    
    if [[ -f "$SINGBOX_INSTALL_DIR/.warp_wireguard.json" ]]; then
        if ! local wg_ep=$(apply_warp_wireguard_config); then
            yellow "警告: WARP 配置加载失败, 将创建不带 WARP 的默认配置。"
        else
            endpoints_json=$wg_ep
            route_rules=$SINGBOX_DIRECT_ROUTE_RULES
            route_rules=${route_rules//__WARP_DOMAIN_SUFFIX_LIST__/$(get_warp_domain_list)}
        fi
    fi
    
    base_config=${base_config/__ENDPOINTS__/$endpoints_json}
    base_config=${base_config/__ROUTE_RULES__/$route_rules}
    printf '%s\n' "$base_config" > "$SINGBOX_INSTALL_DIR/singbox.json"
    log "已创建初始 Sing-box 基础配置文件: $SINGBOX_INSTALL_DIR/singbox.json"
    return 0  # 已创建
}

# -----------------------------------------------------------------------------
# 确保所有 Systemd 服务模板文件都已创建
# -----------------------------------------------------------------------------
ensure_template_files() {
    local need_reload=false

    # KCPTUN 服务模板
    local kcp_content="[Unit]
Description=KCPTUN Instance Server (Instance %i)
After=network.target
[Service]
Type=simple
ExecStart=${KCP_INSTALL_DIR}/kcptun_server -c ${KCP_INSTALL_DIR}/kcptun_%i.json
Restart=always
RestartSec=3
[Install]
WantedBy=multi-user.target"
    
    if update_service_template "$kcp_content" "$KCPTUN_TEMPLATE_FILE"; then
        need_reload=true
    fi

    # UDP2RAW 服务模板
    local udp_content="[Unit]
Description=UDP2RAW Instance Server (Instance %i)
After=network.target
[Service]
Type=simple
ExecStart=${UDP2RAW_INSTALL_DIR}/udp2raw --conf-file ${UDP2RAW_INSTALL_DIR}/udp2raw_%i.conf
AmbientCapabilities=CAP_NET_ADMIN CAP_NET_BIND_SERVICE CAP_NET_RAW
CapabilityBoundingSet=CAP_NET_ADMIN CAP_NET_BIND_SERVICE CAP_NET_RAW
Restart=always
RestartSec=3
[Install]
WantedBy=multi-user.target"
    
    if update_service_template "$udp_content" "$UDP2RAW_TEMPLATE_FILE"; then
        need_reload=true
    fi

    generate_self_signed_cert

    # Sing-box 服务模板
    local singbox_content="[Unit]
Description=Sing-box Service
After=network.target
[Service]
Type=simple
ExecStart=${SINGBOX_INSTALL_DIR}/sing-box run -c ${SINGBOX_INSTALL_DIR}/singbox.json
AmbientCapabilities=CAP_NET_ADMIN CAP_NET_BIND_SERVICE CAP_NET_RAW
CapabilityBoundingSet=CAP_NET_ADMIN CAP_NET_BIND_SERVICE CAP_NET_RAW
Restart=always
RestartSec=3
[Install]
WantedBy=multi-user.target"
    
    if update_service_template "$singbox_content" "$SINGBOX_TEMPLATE_FILE"; then
        need_reload=true
    fi

    # 创建初始 Sing-box 配置
    if create_initial_singbox_config; then
        need_reload=true
    fi

    if [[ "$need_reload" == true ]]; then
        systemctl daemon-reload
    fi
}

# -----------------------------------------------------------------------------
# 安全跟踪 systemd 日志, 保护原 SIGINT trap
# 参数: 所有参数透传给 journalctl
# 限制 journalctl 输出行数 (默认 1000 行), 避免被 SIGPIPE 杀死后留下孤儿进程
# -----------------------------------------------------------------------------
follow_journal_safely() {
    local saved_trap
    saved_trap=$(trap -p SIGINT)
    trap ':' SIGINT
    # --no-tail 让 Ctrl+C 后能正常退出而不是被 SIGPIPE 杀死
    journalctl --no-tail -n 1000 "$@" -f 2>/dev/null || true
    if [[ -n "$saved_trap" ]]; then
        eval "$saved_trap"
    else
        trap - SIGINT
    fi
}

# -----------------------------------------------------------------------------
# 从配置文件/服务中提取监听信息 (用于显示状态)
# -----------------------------------------------------------------------------
get_listen_info_from_conf() {
    local conf_path=$1
    if [[ ! -f "$conf_path" ]]; then echo "配置文件不存在"; return; fi

    if [[ "$conf_path" == *".json" ]]; then
        if grep -q '"smuxver"' "$conf_path" 2>/dev/null; then
            grep -Po '(?<="listen": ")[^"]+' "$conf_path"
        elif jq -e '.inbounds[0].listen_port' "$conf_path" >/dev/null 2>&1; then
            local port=$(jq -r '.inbounds[0].listen_port // 0' "$conf_path" 2>/dev/null)
            echo "0.0.0.0:${port}"
        else
            local listen=$(jq -r '.inbounds[0].listen // "0.0.0.0"' "$conf_path" 2>/dev/null)
            local port=$(jq -r '.inbounds[0].port // 0' "$conf_path" 2>/dev/null)
            if [[ "$listen" == "null" || "$port" == "0" ]]; then echo "JSON解析错误"; else echo "${listen}:${port}"; fi
        fi
    elif [[ "$conf_path" == *".conf" ]]; then
        grep -Po '(?<=-l )[^ ]+' "$conf_path"
    fi
}

# -----------------------------------------------------------------------------
# 从配置文件中检查 WARP 是否启用
# -----------------------------------------------------------------------------
get_warp_status_from_conf() {
    local conf_path=$1
    if jq -e '.endpoints[] | select(.tag == "warp-ep" and .type == "wireguard")' "$conf_path" >/dev/null 2>&1; then echo "已启用WARP"; else echo "未启用WARP"; fi
}

# -----------------------------------------------------------------------------
# 获取单个服务的运行状态字符串 (绿色或黄色)
# -----------------------------------------------------------------------------
get_service_status_string() {
    local service_name=$1
    if systemctl is-active --quiet "$service_name"; then echo "运行中"; else echo "未运行"; fi
}

# -----------------------------------------------------------------------------
# 获取串联实例的组合状态 (颜色, 状态1, 状态2)
# -----------------------------------------------------------------------------
get_chain_status_tuple() {
    local chain_type=$1 chain_id=$2
    local service1_name="ax-singbox.service"
    local service2_name="ax-udp2raw@${chain_id}.service"

    local s1_active=false s2_active=false status_color="yellow"
    local hy2_tag="hy2-c${chain_id#c}"
    if systemctl is-active --quiet "$service1_name" && \
       jq -e --arg tag "$hy2_tag" '.inbounds[] | select(.tag == $tag)' "$SINGBOX_INSTALL_DIR/singbox.json" >/dev/null 2>&1; then
        s1_active=true
    fi
    if systemctl is-active --quiet "$service2_name"; then s2_active=true; fi
    if [[ "$s1_active" == "true" && "$s2_active" == "true" ]]; then status_color="cyan"; fi

    echo "$status_color $(get_service_status_string "$service1_name") $(get_service_status_string "$service2_name")"
}

# -----------------------------------------------------------------------------
# 获取 3 组件串联实例的组合状态 (颜色, 状态1, 状态2, 状态3)
# -----------------------------------------------------------------------------
get_3_chain_status_tuple() {
    local chain_id=$1 # e.g., s3c1
    local ss_tag="ss-s3c${chain_id#s3c}"
    local service2_name="ax-kcptun@${chain_id}.service"        # KCPTUN
    local service3_name="ax-udp2raw@${chain_id}.service"       # UDP2RAW

    local s1_active=false s2_active=false s3_active=false status_color="yellow"
    # SS inbound is managed inside sing-box; check if ax-singbox.service is running and inbound exists
    if systemctl is-active --quiet ax-singbox.service && \
       jq -e --arg tag "$ss_tag" '.inbounds[] | select(.tag == $tag)' "$SINGBOX_INSTALL_DIR/singbox.json" >/dev/null 2>&1; then
        s1_active=true
    fi
    if systemctl is-active --quiet "$service2_name"; then s2_active=true; fi
    if systemctl is-active --quiet "$service3_name"; then s3_active=true; fi

    # 修复: 原代码 $s1_active 是变量值求值, 不是条件测试, 导致 s1_status 永远是 "运行中"
    local s1_status="未运行"
    [[ "$s1_active" == "true" ]] && s1_status="运行中"
    if [[ "$s1_active" == "true" && "$s2_active" == "true" && "$s3_active" == "true" ]]; then status_color="cyan"; fi
    
    echo "$status_color $s1_status $(get_service_status_string "$service2_name") $(get_service_status_string "$service3_name")"
}

INSTANCE_NAMES_FILE="/etc/ax-instance-names.json"
SERVER_ADDR_FILE="/etc/ax-server-addr.json"

get_custom_server_addr() {
    local key=$1
    [[ ! -f "$SERVER_ADDR_FILE" ]] && echo "" && return
    jq -r --arg k "$key" '.[$k] // ""' "$SERVER_ADDR_FILE" 2>/dev/null
}

set_custom_server_addr() {
    local key=$1 addr=$2; local tmp
    if [[ -f "$SERVER_ADDR_FILE" ]]; then
        tmp=$(jq -c --arg k "$key" --arg v "$addr" '.[$k] = $v' "$SERVER_ADDR_FILE" 2>/dev/null)
    else
        tmp=$(jq -c -n --arg k "$key" --arg v "$addr" '{($k): $v}')
    fi
    echo "$tmp" > "$SERVER_ADDR_FILE"
}

remove_custom_server_addr() {
    local key=$1
    [[ ! -f "$SERVER_ADDR_FILE" ]] && return
    local tmp=$(jq -c "del(.\"$key\")" "$SERVER_ADDR_FILE" 2>/dev/null)
    echo "$tmp" > "$SERVER_ADDR_FILE"
}

get_global_server_addr() {
    get_custom_server_addr "_default"
}

set_global_server_addr() {
    set_custom_server_addr "_default" "$1"
}

get_instance_server_addr() {
    local type=$1 id=$2; local key="${type}_${id}"
    local custom=$(get_custom_server_addr "$key")
    if [[ -n "$custom" ]]; then
        echo "$custom"
    else
        get_public_ip
    fi
}

# 验证域名格式
validate_domain() {
    local domain=$1
    if [[ "$domain" =~ ^[0-9]+\.[0-9]+\.[0-9]+\.[0-9]+$ ]]; then return 0; fi
    if [[ "$domain" =~ ^[a-zA-Z0-9]([a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(\.[a-zA-Z0-9]([a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)*$ ]]; then return 0; fi
    return 1
}

check_domain_points_to_vps() {
    local domain=$1 vps_ip=$2
    if command -v dig &>/dev/null; then
        dig +short "$domain" 2>/dev/null | grep -E '^[0-9]+\.[0-9]+\.[0-9]+\.[0-9]+$' | head -1
    elif command -v host &>/dev/null; then
        host "$domain" 2>/dev/null | grep "has address" | head -1 | awk '{print $NF}'
    elif command -v nslookup &>/dev/null; then
        nslookup "$domain" 2>/dev/null | grep "Address:" | tail -1 | awk '{print $2}'
    elif command -v getent &>/dev/null; then
        getent ahosts "$domain" 2>/dev/null | head -1 | awk '{print $1}'
    fi
}

prompt_server_address() {
    local type=$1 id=$2; local key="${type}_${id}"
    local global_addr=$(get_global_server_addr)
    local vps_ip=$(get_public_ip)
    local default="${global_addr:-$vps_ip}"
    local existing=$(get_custom_server_addr "$key")
    local prompt_default="${existing:-$default}"
    while true; do
        read -p "请输入域名或IP (留空则使用 ${prompt_default}): " user_addr
        if [[ -z "$user_addr" ]]; then
            set_custom_server_addr "$key" "$prompt_default"
            green "使用地址: $prompt_default"
            return
        fi
        if ! validate_domain "$user_addr"; then
            red "格式无效，请重新输入！"
            continue
        fi
        if [[ "$user_addr" =~ ^[0-9]+\.[0-9]+\.[0-9]+\.[0-9]+$ ]]; then
            set_custom_server_addr "$key" "$user_addr"
            set_global_server_addr "$user_addr"
            green "使用地址: $user_addr"
            return
        fi
        local resolved
        resolved=$(check_domain_points_to_vps "$user_addr" "$vps_ip")
        if [[ -z "$resolved" ]]; then
            yellow "无法解析域名，将使用: $user_addr (请确认 DNS 已配置)"
            set_custom_server_addr "$key" "$user_addr"
            set_global_server_addr "$user_addr"
            return
        elif [[ "$resolved" == "$vps_ip" ]]; then
            set_custom_server_addr "$key" "$user_addr"
            set_global_server_addr "$user_addr"
            green "使用地址: $user_addr"
            return
        else
            red "域名 $user_addr 解析到 $resolved，与 VPS IP ($vps_ip) 不匹配！请重新输入。"
        fi
    done
}

get_custom_instance_name() {
    local key=$1
    [[ ! -f "$INSTANCE_NAMES_FILE" ]] && echo "" && return
    jq -r --arg k "$key" '.[$k] // ""' "$INSTANCE_NAMES_FILE" 2>/dev/null
}

set_custom_instance_name() {
    local key=$1 name=$2; local tmp
    if [[ -f "$INSTANCE_NAMES_FILE" ]]; then
        tmp=$(jq -c --arg k "$key" --arg v "$name" '.[$k] = $v' "$INSTANCE_NAMES_FILE" 2>/dev/null) || { red "jq 执行失败" >&2; return 1; }
    else
        tmp=$(jq -c -n --arg k "$key" --arg v "$name" '{($k): $v}') || { red "jq 执行失败" >&2; return 1; }
    fi
    [[ -n "$tmp" ]] || { red "错误: jq 返回空结果" >&2; return 1; }
    echo "$tmp" > "$INSTANCE_NAMES_FILE"
    green "实例名称已设置为: $name"
}

remove_custom_instance_name() {
    local key=$1
    [[ ! -f "$INSTANCE_NAMES_FILE" ]] && return
    local tmp=$(jq -c "del(.\"$key\")" "$INSTANCE_NAMES_FILE" 2>/dev/null)
    echo "$tmp" > "$INSTANCE_NAMES_FILE"
}

# -----------------------------------------------------------------------------
# 清理单个实例关联的所有敏感文件 (密码/WARP 密钥/Reality 密钥/自签证书)
# 参数: $1=实例类型, $2=实例 ID
# 补充: hinst_id 只在 hysteria2/hy2_chain 类型中有效, 用于定位 .reality_keys.json / hy2 密码文件
# -----------------------------------------------------------------------------
cleanup_instance_secrets() {
    local type=$1 id=$2
    case "$type" in
        udp2raw)
            systemctl stop "ax-udp2raw@${id}.service" 2>/dev/null
            systemctl disable "ax-udp2raw@${id}.service" 2>/dev/null
            rm -f "$UDP2RAW_INSTALL_DIR/last_udp2raw_pass.txt"
            rm -f "$UDP2RAW_INSTALL_DIR/udp2raw_${id}.conf"
            ;;
        kcptun)
            systemctl stop "ax-kcptun@${id}.service" 2>/dev/null
            systemctl disable "ax-kcptun@${id}.service" 2>/dev/null
            rm -f "$KCP_INSTALL_DIR/last_kcptun_pass.txt"
            rm -f "$KCP_INSTALL_DIR/kcptun_${id}.json"
            ;;
        xray_reality)
            # 删除 Reality 密钥存储中对应 tag 的项
            local tag="vless-reality-${id}"
            if [[ -f "$SINGBOX_REALITY_KEYS_FILE" ]]; then
                local tmp=$(jq -c --arg tag "$tag" 'del(.[$tag])' "$SINGBOX_REALITY_KEYS_FILE" 2>/dev/null)
                echo "$tmp" > "$SINGBOX_REALITY_KEYS_FILE"
            fi
            ;;
        hysteria2)
            rm -f "$SINGBOX_INSTALL_DIR/last_hy2_pass.txt"
            ;;
        ss_3_chain_chain)
            systemctl stop "ax-kcptun@s3c${id}.service" "ax-udp2raw@s3c${id}.service" 2>/dev/null
            systemctl disable "ax-kcptun@s3c${id}.service" "ax-udp2raw@s3c${id}.service" 2>/dev/null
            rm -f "$KCP_INSTALL_DIR/kcptun_s3c${id}.json"
            rm -f "$UDP2RAW_INSTALL_DIR/udp2raw_s3c${id}.conf"
            ;;
        hy2_chain)
            systemctl stop "ax-udp2raw@c${id}.service" 2>/dev/null
            systemctl disable "ax-udp2raw@c${id}.service" 2>/dev/null
            rm -f "$UDP2RAW_INSTALL_DIR/udp2raw_c${id}.conf"
            ;;
    esac
}

# -----------------------------------------------------------------------------
# 清理 WARP WireGuard 密钥 (全剧只一份, 所有实例共享)
# 仅在最后一个 sing-box inbound 被删除时调用
# -----------------------------------------------------------------------------
cleanup_warp_secrets_if_orphan() {
    # 如果 singbox.json 仍包含任何 inbound 则保留 WARP 密钥
    if [[ -f "$SINGBOX_INSTALL_DIR/singbox.json" ]]; then
        local count=$(jq -r '.inbounds | length' "$SINGBOX_INSTALL_DIR/singbox.json" 2>/dev/null)
        if [[ -n "$count" && "$count" -gt 0 ]]; then return; fi
    fi
    rm -f "$SINGBOX_INSTALL_DIR/.warp_wireguard.json"
    rm -f "$SINGBOX_REALITY_KEYS_FILE"
    yellow "已清理孤立的 WARP 密钥与 Reality 密钥文件。"
}

generate_instance_display_name() {
    local type=$1 id=$2
    local ip=$(get_instance_server_addr "$type" "$id")
    case "$type" in
        udp2raw) echo "UDP2RAW_${ip}_${id}" ;;
        kcptun) echo "KCP_${ip}_${id}" ;;
        xray_reality) echo "VLESS_${ip}_${id}" ;;
        hysteria2) echo "HY2_${ip}_${id}" ;;
        hy2_chain) echo "HY2_UDP_${ip}_${id}" ;;
        ss_3_chain_chain) echo "SS_KCP_UDP_${ip}_${id}" ;;
        *) echo "${type}_${id}" ;;
    esac
}

get_instance_display_name() {
    local type=$1 id=$2; local key="${type}_${id}"
    local custom_name=$(get_custom_instance_name "$key")
    if [[ -n "$custom_name" ]]; then echo "$custom_name"; else generate_instance_display_name "$type" "$id"; fi
}

prompt_custom_instance_name() {
    local type=$1 id=$2; local default_name=$(generate_instance_display_name "$type" "$id")
    read -p "请输入实例名称 (留空则使用默认: ${default_name}): " custom_name
    if [[ -n "$custom_name" ]]; then set_custom_instance_name "${type}_${id}" "$custom_name"; fi
}

interactive_rename_instance() {
    local type=$1 id=$2; local key="${type}_${id}"
    local current=$(get_instance_display_name "$type" "$id")
    echo "当前名称: $(cyan "$current")"
    read -p "请输入新名称 (留空恢复默认): " new_name
    if [[ -z "$new_name" ]]; then
        remove_custom_instance_name "$key"
        green "已恢复默认名称"
    else
        set_custom_instance_name "$key" "$new_name"
    fi
}

# -----------------------------------------------------------------------------
# 显示单个实例的状态行 (用于主菜单)
# -----------------------------------------------------------------------------
display_instance_status_line() {
    local type=$1 id=$2 prefix=$3; local line; local name=$(get_instance_display_name "$type" "$id")
    case "$type" in
        "hy2_chain")
            local full_id="c${id}"
            read -r color hy2_status udp_status <<< "$(get_chain_status_tuple "hy2" "$full_id")"
            local udp_info=$(get_listen_info_from_conf "$UDP2RAW_INSTALL_DIR/udp2raw_${full_id}.conf")
            local warp_status=$(get_warp_status_from_conf "$SINGBOX_INSTALL_DIR/singbox.json")
            line="$($color "${prefix}${name}:  Hysteria2 [${hy2_status}] + UDP2RAW [${udp_status}] ${udp_info} (${warp_status})")"
            ;;
        "ss_3_chain_chain")
            local full_id="s3c${id}"
            read -r color s1_status s2_status s3_status <<< "$(get_3_chain_status_tuple "$full_id")"
            local udp_info=$(get_listen_info_from_conf "$UDP2RAW_INSTALL_DIR/udp2raw_${full_id}.conf")
            local warp_status=$(get_warp_status_from_conf "$SINGBOX_INSTALL_DIR/singbox.json")
            line="$($color "${prefix}${name}:  SS [${s1_status}] + KCP [${s2_status}] + UDP2RAW [${s3_status}] ${udp_info} (${warp_status})")"
            ;;
        "udp2raw"|"kcptun"|"xray_reality"|"hysteria2")
            local conf_file service_prefix title; local color_func="yellow"
            case "$type" in
                udp2raw) conf_file="$UDP2RAW_INSTALL_DIR/udp2raw_${id}.conf"; service_prefix="ax-udp2raw"; title="UDP2RAW";;
                kcptun) conf_file="$KCP_INSTALL_DIR/kcptun_${id}.json"; service_prefix="ax-kcptun"; title="KCPTUN";;
                xray_reality) conf_file="$SINGBOX_INSTALL_DIR/singbox.json"; service_prefix="ax-singbox"; title="VLESS+Reality";;
                hysteria2) conf_file="$SINGBOX_INSTALL_DIR/singbox.json"; service_prefix="ax-singbox"; title="Hysteria2";;
            esac
            local status_info=""
            if [[ "$type" == "xray_reality" || "$type" == "hysteria2" ]]; then
                local tag
                case "$type" in xray_reality) tag="vless-reality-${id}";; hysteria2) tag="hy2-${id}";; esac
                local port=$(jq -r --arg tag "$tag" '.inbounds[] | select(.tag == $tag) | .listen_port' "$conf_file" 2>/dev/null)
                status_info="0.0.0.0:${port}"
            else
                status_info=$(get_listen_info_from_conf "$conf_file")
            fi
            local status_str=$(get_service_status_string "$service_prefix")
            local extra_info=""
            if [[ "$type" == "xray_reality" || "$type" == "hysteria2" ]]; then
                extra_info=" ($(get_warp_status_from_conf "$SINGBOX_INSTALL_DIR/singbox.json"))"
            fi
            if [[ "$status_str" == "运行中" ]]; then color_func="cyan"; fi
            line="$($color_func "${prefix}${name}:  ${title} [${status_str}] ${status_info}${extra_info}")"
            ;;
    esac
    echo -e "$line"
}

# -----------------------------------------------------------------------------
# 获取指定目录下的所有实例 ID (内部函数)
# -----------------------------------------------------------------------------
get_instances() {
    local dir=$1 pattern=$2
    find "$dir" -maxdepth 1 -name "$pattern" 2>/dev/null -printf '%f\n' | sed -E "s/.*_([a-zA-Z0-9]+)\..*/\1/" | sort -V
}

# -----------------------------------------------------------------------------
# 获取 *独立* 实例的 ID 列表 (过滤掉串联实例)
# -----------------------------------------------------------------------------
get_standalone_instances() {
    local type_lowercase=$1
    local dir="" pattern=""
    local standalone_instances=()
    
    local config_file="$SINGBOX_INSTALL_DIR/singbox.json"
    case "$type_lowercase" in
        "xray_reality")
            if [[ -f "$config_file" ]]; then
                local ids=$(jq -r '.inbounds[] | select(.type == "vless" and .tls.reality.enabled == true) | .tag | split("-")[2]' "$config_file" 2>/dev/null)
                echo "$ids"
            fi
            return
            ;;
        "hysteria2")
            if [[ -f "$config_file" ]]; then
                local ids=$(jq -r '.inbounds[] | select(.type == "hysteria2") | .tag | split("-")[1] | select(test("^[0-9]+$"))' "$config_file" 2>/dev/null)
                echo "$ids"
            fi
            return
            ;;
        "udp2raw") dir="$UDP2RAW_INSTALL_DIR"; pattern="udp2raw_*.conf";;
        "kcptun") dir="$KCP_INSTALL_DIR"; pattern="kcptun_*.json";;
    esac

    local all_instances=$(get_instances "$dir" "$pattern")
    for i in $all_instances; do
        if [[ ! "$i" =~ ^(c|s3c)[0-9]+$ ]]; then
            standalone_instances+=($i)
        fi
    done
    echo "${standalone_instances[@]}"
}


# =============================================================================
# 15. 实例管理菜单与操作
# =============================================================================

# -----------------------------------------------------------------------------
# 管理单个独立实例的子菜单
# -----------------------------------------------------------------------------
manage_instance_menu() {
    local type=$1 id=$2 service=$3 conf=$4; local disp_name=$(get_instance_display_name "$type" "$id")
    while true; do
        clear; echo "=================================="; echo "      ${disp_name}  $(dim "(${type^^} ${id})")"; echo "=================================="
        local status_info=""
        if [[ "$type" == "xray_reality" || "$type" == "hysteria2" ]]; then
            local tag; case "$type" in xray_reality) tag="vless-reality-${id}";; hysteria2) tag="hy2-${id}";; esac
            local port=$(jq -r --arg tag "$tag" '.inbounds[] | select(.tag == $tag) | .listen_port' "$conf" 2>/dev/null)
            status_info="0.0.0.0:${port}"
        fi
        echo "状态：$(get_service_status_string "$service") $(dim "$status_info")"
        if [[ "$type" == "xray_reality" ]]; then cyan "订阅链接: $(generate_singbox_reality_link $id)"; fi
        if [[ "$type" == "hysteria2" ]]; then cyan "订阅链接: $(generate_singbox_hy2_link $id)"; fi
        echo "----------------------------------"; echo "1) 启动/重启此实例"; echo "2) 停止此实例"; echo "3) 查看实时日志"; echo "4) 编辑配置文件"; echo "5) 修改实例名称"; echo "6) 查看客户端配置"; echo "99) 彻底删除此实例"; echo "0) 返回"
        read -p "请选择 [0-6, 99]: " choice
        case $choice in
            1) log "正在启动/重启..."; systemctl restart "$service"; green "操作完成！";;
            2) log "正在停止..."; systemctl stop "$service"; green "操作完成！";;
            3)
                log "正在实时跟踪日志... (按 Ctrl+C 仅退出日志)"
                sleep 1
                follow_journal_safely -u "$service" --since "1 hour ago"
                ;;
            4) nano "$conf"; log "重启实例以应用配置..."; systemctl restart "$service"; green "配置已更新！";;
            5) interactive_rename_instance "$type" "$id"; read -p $'\n按任意键返回...' -n1 -s;;
            99) read -p "确认彻底删除实例 ${id}？(默认"否") [y/N]: " confirm
                if [[ "$confirm" == "y" || "$confirm" == "Y" ]]; then
                    if [[ "$type" == "xray_reality" || "$type" == "hysteria2" ]]; then
                        local tag; case "$type" in xray_reality) tag="vless-reality-${id}";; hysteria2) tag="hy2-${id}";; esac
                        remove_singbox_inbound "$tag"
                    else
                        systemctl stop "$service" 2>/dev/null
                        systemctl disable "$service" >/dev/null 2>&1
                        rm -f "$conf"
                    fi
                    cleanup_instance_secrets "$type" "$id"
                    remove_custom_instance_name "${type}_${id}"
                    remove_custom_server_addr "${type}_${id}"
                    cleanup_warp_secrets_if_orphan
                    systemctl daemon-reload
                    green "实例 ${id} 已删除！"; break
                fi;;
             6) clear; echo "--- ${type^^} 客户端配置 (实例 $id) ---"
                case "$type" in
                    "udp2raw") view_udp2raw_client_config "$id" ;;
                    "kcptun") view_kcptun_client_config "$id" ;;
                    "xray_reality") cyan "订阅链接: $(generate_singbox_reality_link "$id")" ;;
                    "hysteria2") cyan "订阅链接: $(generate_singbox_hy2_link "$id")" ;;
                esac
               read -p $'\n按任意键返回...' -n1 -s;;
            0) break;; *) red "无效输入";;
        esac
        [[ "$choice" == "1" || "$choice" == "2" || "$choice" == "4" ]] && read -p $'\n按任意键返回...' -n1 -s
    done
}

# 收集 UDP2RAW/KCPTUN 通用配置
collect_common_instance_config() {
    local type=$1
    local next_id=$(find_next_available_id "$type")
    
    case "$type" in
        udp2raw) 
            TITLE="UDP2RAW"
            SERVICE_PREFIX="udp2raw"
            SYSTEMD_SERVICE_NAME="ax-udp2raw"
            FILE_EXT="conf"
            CONFIG_TEMPLATE="$UDP2RAW_CONFIG_TEMPLATE"
            ;;
        kcptun)
            TITLE="KCPTUN"
            SERVICE_PREFIX="kcptun"
            SYSTEMD_SERVICE_NAME="ax-kcptun"
            FILE_EXT="json"
            CONFIG_TEMPLATE="$KCPTUN_CONFIG_JSON_TEMPLATE"
            ;;
        *)
            red "内部错误: 无效的实例类型 '$type'"
            return 1
            ;;
    esac
    
    log "启动一个新的 ${TITLE} 实例..."
    green "新实例将被创建为: ax-${SYSTEMD_SERVICE_NAME}@${next_id}.service"
    
    prompt_custom_instance_name "$type" "$next_id"
    prompt_server_address "$type" "$next_id"
    
    # 收集通用配置
    declare -A replacements
    
    read -p "请输入监听地址 (默认: $DEFAULT_LISTEN_ADDR): " listen_addr_input
    listen_addr=${listen_addr_input:-$DEFAULT_LISTEN_ADDR}
    read_valid_port "请输入监听端口 (留空则随机生成): " listen_port true
    
    read -p "请输入目标地址 (默认: $DEFAULT_TARGET_ADDR): " target_host
    target_host=${target_host:-$DEFAULT_TARGET_ADDR}
    read_valid_port "请输入目标端口 (留空则随机生成): " target_port true
    
    if [[ "$type" == "udp2raw" ]]; then
        replacements["__LISTEN_ADDR__"]="${listen_addr}:${listen_port}"
        replacements["__TARGET_ADDR__"]="${target_host}:${target_port}"
        
        local udp_params=$(collect_udp2raw_params)
        IFS='|' read -r raw_mode cipher_mode auth_mode <<< "$udp_params"
        replacements["__RAW_MODE__"]="$raw_mode"
        replacements["__CIPHER_MODE__"]="$cipher_mode"
        replacements["__AUTH_MODE__"]="$auth_mode"
        
        local password=$(handle_password_input "$type")
        replacements["__PASSWORD__"]="$password"
    else
        replacements["__LISTEN__"]="${listen_addr}:${listen_port}"
        replacements["__TARGET__"]="${target_host}:${target_port}"
        
        local kcp_params=$(collect_kcptun_params)
        IFS='|' read -r mode crypt tcp_enabled mtu sndwnd rcvwnd <<< "$kcp_params"
        replacements["__MODE__"]="$mode"
        replacements["__CRYPT__"]="$crypt"
        replacements["__TCP__"]="$tcp_enabled"
        replacements["__MTU__"]="$mtu"
        replacements["__SNDWND__"]="$sndwnd"
        replacements["__RCVWND__"]="$rcvwnd"
        replacements["__NOCOMP__"]="true"
        
        local password=$(handle_password_input "$type")
        password=$(json_escape "$password")
        replacements["__KEY__"]="$password"
    fi
    
    # 生成配置文件
    log "生成配置文件..."
    local temp_config="$CONFIG_TEMPLATE"
    local conf_path="${INSTALL_DIR}/${SERVICE_PREFIX}_${next_id}.${FILE_EXT}"
    
    for placeholder in "${!replacements[@]}"; do
        temp_config="${temp_config//${placeholder}/${replacements[${placeholder}]}}"
    done
    printf '%s\n' "$temp_config" > "$conf_path"

    sync
    log "启动服务..."
    systemctl enable --now "${SYSTEMD_SERVICE_NAME}@${next_id}.service"
    sleep 1
    green "实例 ${next_id} 已启动！"
    echo
    
    case "$type" in
        udp2raw) view_udp2raw_client_config "$next_id" ;;
        kcptun) view_kcptun_client_config "$next_id" ;;
    esac
}

# -----------------------------------------------------------------------------
# 创建一个新的独立实例 (Hysteria2, UDP2RAW, KCPTUN)
# -----------------------------------------------------------------------------
create_new_instance() {
    local type=$1
    collect_common_instance_config "$type"
}

# 生成并保存 Reality 密钥对
generate_and_save_reality_keypair() {
    local tag=$1
    log "正在生成 Reality 密钥对..." >&2
    local tmp_key=$("$SINGBOX_INSTALL_DIR/sing-box" generate reality-keypair 2>/dev/null)
    if [[ -z "$tmp_key" ]]; then
        red "错误: sing-box generate reality-keypair 失败！" >&2
        return 1
    fi
    local private_key=$(echo "$tmp_key" | grep "PrivateKey" | awk '{print $2}')
    local public_key=$(echo "$tmp_key" | grep "PublicKey" | awk '{print $2}')
    if [[ -z "$private_key" || -z "$public_key" ]]; then
        red "错误: 无法解析 Reality 密钥对！" >&2
        return 1
    fi
    save_reality_keypair "$tag" "$private_key" "$public_key"
    echo "$private_key"
}

# -----------------------------------------------------------------------------
# 添加一个新的 Sing-box inbound (Reality, Hysteria2)
# -----------------------------------------------------------------------------
add_singbox_inbound() {
    local type=$1
    local next_id=$(find_next_available_id "singbox")
    
    prompt_custom_instance_name "$type" "$next_id"
    prompt_server_address "$type" "$next_id"
    
    local inbound_json="" tag=""
    
    if [[ "$type" == "xray_reality" ]]; then
        tag="vless-reality-${next_id}"
        log "添加一个新的 VLESS+Reality inbound, tag: $tag"
        
        local listen_port
        read_valid_port "请输入监听端口 (留空则随机): " listen_port true
        
        local uuid=$(generate_strong_password)
        local private_key=$(generate_and_save_reality_keypair "$tag") || return 1
        local short_id=$(openssl rand -hex 8)
        
        inbound_json=$SINGBOX_VLESS_REALITY_TEMPLATE
        inbound_json=${inbound_json/__ID__/$next_id}
        inbound_json=${inbound_json/__LISTEN_PORT__/$listen_port}
        inbound_json=${inbound_json/__UUID__/$uuid}
        inbound_json=${inbound_json/__REALITY_FLOW__/$SINGBOX_REALITY_DEFAULT_FLOW}
        inbound_json=${inbound_json//__SNI__/$SINGBOX_REALITY_DEFAULT_SNI}
        inbound_json=${inbound_json/__PRIVATE_KEY__/$private_key}
        inbound_json=${inbound_json/__SHORT_ID__/$short_id}
        
    elif [[ "$type" == "hysteria2" ]]; then
        tag="hy2-${next_id}"
        log "添加一个新的 Hysteria2 inbound, tag: $tag"
        
        local listen_port
        read_valid_port "请输入监听端口 (留空则随机): " listen_port true
        local hy2_password=$(handle_password_input "hysteria2")
        hy2_password=$(json_escape "$hy2_password")
        
        inbound_json=$SINGBOX_HYSTERIA2_TEMPLATE
        inbound_json=${inbound_json/__ID__/$next_id}
        inbound_json=${inbound_json/__LISTEN_PORT__/$listen_port}
        inbound_json=${inbound_json/__PASSWORD__/$hy2_password}
        inbound_json=${inbound_json/__SNI__/$HY2_SNI}
        inbound_json=${inbound_json/__KEY_PATH__/$HY2_KEY_PATH}
        inbound_json=${inbound_json/__CERT_PATH__/$HY2_CERT_PATH}
    fi

    if [[ -z "$inbound_json" ]]; then
        red "错误: 未知的 inbound 类型 '$type'"
        return 1
    fi

    local config_file="$SINGBOX_INSTALL_DIR/singbox.json"
    if [[ ! -f "$config_file" ]]; then
        red "错误: 基础配置文件 $config_file 不存在！请先安装 Sing-box。"
        return 1
    fi

    log "将 inbound 添加到 singbox.json..."
    if ! safe_add_singbox_inbound "$inbound_json" "$config_file"; then
        red "添加 inbound 失败, 操作已回滚。" >&2
        return 1
    fi

    sync
    log "重启 Sing-box 服务..."
    systemctl restart ax-singbox.service
    sleep 1
    
    if ! systemctl is-active --quiet ax-singbox.service; then
        red "Sing-box 重启失败！请检查配置或日志。"
        log "journalctl -u ax-singbox.service -n 20"
        return 1
    fi
    
    green "Inbound '$tag' 已添加！Sing-box 运行正常。"
    echo
    
    if [[ "$type" == "xray_reality" ]]; then
        cyan "订阅链接: $(generate_singbox_reality_link "$next_id")"
    elif [[ "$type" == "hysteria2" ]]; then
        cyan "订阅链接: $(generate_singbox_hy2_link "$next_id")"
    fi
}

# -----------------------------------------------------------------------------
# 安全地将 inbound 添加到 singbox.json
# 参数: $1=inbound JSON 字符串, $2=singbox.json 路径
# 步骤: 备份原文件 -> 预校验 inbound JSON -> jq 合并 -> 预校验输出 -> 原子替换
# -----------------------------------------------------------------------------
safe_add_singbox_inbound() {
    local inbound_json=$1 config_file=$2
    if [[ ! -f "$config_file" ]]; then
        red "错误: singbox.json 不存在 ($config_file)" >&2
        return 1
    fi
    if ! command -v python3 &>/dev/null; then
        red "错误: python3 未安装。" >&2
        return 1
    fi
    # 预校验 inbound JSON 合法性
    if ! echo "$inbound_json" | python3 -c "import json,sys; json.load(sys.stdin)" 2>/dev/null; then
        red "错误: 生成的 inbound JSON 不合法，操作取消。" >&2
        return 1
    fi
    # 备份原文件
    local backup="${config_file}.bak.$(date +%s)"
    cp -p "$config_file" "$backup" 2>/dev/null || cp "$config_file" "$backup"
    local tmpfile=$(umask 077 && mktemp) || { red "无法创建临时文件" >&2; return 1; }
    local inbound_tmp=$(umask 077 && mktemp) || { red "无法创建临时文件" >&2; rm -f "$tmpfile"; return 1; }
    printf '%s\n' "$inbound_json" > "$inbound_tmp"
    if ! python3 -c "
import json,sys
cfg = json.load(open('$config_file'))
inbound = json.load(open('$inbound_tmp'))
cfg['inbounds'].append(inbound)
json.dump(cfg, open('$tmpfile','w'), indent=2)
" 2>&1; then
        red "错误: 合并失败，原文件未修改。备份在 $backup" >&2
        echo "=== inbound JSON 内容 ===" >&2
        cat "$inbound_tmp" >&2
        rm -f "$tmpfile" "$inbound_tmp"
        return 1
    fi
    rm -f "$inbound_tmp"
    if ! python3 -c "import json; json.load(open('$tmpfile'))" 2>/dev/null; then
        rm -f "$tmpfile"
        red "错误: 合并输出不是合法 JSON，已回滚。" >&2
        return 1
    fi
    mv "$tmpfile" "$config_file"
    ls -1t "${config_file}.bak."* 2>/dev/null | tail -n +4 | xargs -r rm -f
    return 0
}

# -----------------------------------------------------------------------------
# 从 singbox.json 中移除一个 inbound (通过 tag)
# -----------------------------------------------------------------------------
remove_singbox_inbound() {
    local tag=$1
    local config_file="$SINGBOX_INSTALL_DIR/singbox.json"
    if [[ ! -f "$config_file" ]]; then red "配置文件不存在" >&2; return 1; fi
    if ! command -v python3 &>/dev/null; then red "错误: python3 未安装。" >&2; return 1; fi
    local tmpfile; tmpfile=$(umask 077 && mktemp) || { red "无法创建临时文件" >&2; return 1; }
    if ! python3 -c "
import json,sys
cfg = json.load(open('$config_file'))
cfg['inbounds'] = [i for i in cfg['inbounds'] if i.get('tag') != '$tag']
json.dump(cfg, open('$tmpfile','w'), indent=2)
" 2>/dev/null; then
        rm -f "$tmpfile"
        red "错误: 移除失败" >&2
        return 1
    fi
    mv "$tmpfile" "$config_file"
    systemctl restart ax-singbox.service
    green "Inbound '$tag' 已移除。"
}

# =============================================================================
# 16. 客户端配置与订阅链接生成
# =============================================================================

# -----------------------------------------------------------------------------
# 生成 Hysteria2 订阅链接
# -----------------------------------------------------------------------------
# -----------------------------------------------------------------------------
# Reality 密钥存储文件路径
# -----------------------------------------------------------------------------
SINGBOX_REALITY_KEYS_FILE="$SINGBOX_INSTALL_DIR/.reality_keys.json"

# -----------------------------------------------------------------------------
# 保存 Reality 密钥对
# -----------------------------------------------------------------------------
save_reality_keypair() {
    local tag=$1 private_key=$2 public_key=$3
    local keys_file="$SINGBOX_REALITY_KEYS_FILE"
    mkdir -p "$(dirname "$keys_file")"
    if [[ -f "$keys_file" ]]; then
        local tmp=$(mktemp)
        jq --arg tag "$tag" --arg priv "$private_key" --arg pub "$public_key" \
            '.[$tag] = {"private_key": $priv, "public_key": $pub}' "$keys_file" > "$tmp" && mv "$tmp" "$keys_file"
    else
        echo "{\"$tag\": {\"private_key\": \"$private_key\", \"public_key\": \"$public_key\"}}" > "$keys_file"
    fi
    chmod 600 "$keys_file"
}

# -----------------------------------------------------------------------------
# 获取 Reality 公钥 (从存储文件读取)
# -----------------------------------------------------------------------------
get_reality_public_key() {
    local tag=$1
    local keys_file="$SINGBOX_REALITY_KEYS_FILE"
    if [[ -f "$keys_file" ]]; then
        jq -r --arg tag "$tag" '.[$tag].public_key' "$keys_file" 2>/dev/null
    fi
}

# -----------------------------------------------------------------------------
# 生成 Sing-box VLESS+Reality 分享链接
# -----------------------------------------------------------------------------
generate_singbox_reality_link() {
    local id=$1; local tag="vless-reality-${id}"
    local ip=$(get_instance_server_addr "xray_reality" "$id")
    local conf="$SINGBOX_INSTALL_DIR/singbox.json"
    if [[ ! -s "$conf" ]]; then echo "N/A"; return; fi
    local port=$(jq -r --arg tag "$tag" '.inbounds[] | select(.tag == $tag) | .listen_port' "$conf")
    local uuid=$(jq -r --arg tag "$tag" '.inbounds[] | select(.tag == $tag) | .users[0].uuid' "$conf")
    local sni=$(jq -r --arg tag "$tag" '.inbounds[] | select(.tag == $tag) | .tls.server_name' "$conf")
    local sid=$(jq -r --arg tag "$tag" '.inbounds[] | select(.tag == $tag) | .tls.reality.short_id[0]' "$conf")
    local flow=$(jq -r --arg tag "$tag" '.inbounds[] | select(.tag == $tag) | .users[0].flow' "$conf")
    if [[ -z "$port" || "$port" == "null" || -z "$uuid" || "$uuid" == "null" ]]; then echo "N/A"; return; fi
    local pbk=$(get_reality_public_key "$tag")
    if [[ -z "$pbk" || "$pbk" == "null" ]]; then pbk="MISSING_KEY"; fi
    local link="vless://${uuid}@${ip}:${port}?type=tcp&security=reality&sni=${sni}&pbk=${pbk}&flow=${flow}&sid=${sid}&fp=chrome#Reality_${ip}_${id}"
    echo "$link"
}

# -----------------------------------------------------------------------------
# 生成 Sing-box Hysteria2 分享链接
# -----------------------------------------------------------------------------
generate_singbox_hy2_link() {
    local id=$1; local tag="hy2-${id}"
    local ip=$(get_instance_server_addr "hysteria2" "$id")
    local conf="$SINGBOX_INSTALL_DIR/singbox.json"
    if [[ ! -s "$conf" ]]; then echo "N/A"; return; fi
    local port=$(jq -r --arg tag "$tag" '.inbounds[] | select(.tag == $tag) | .listen_port' "$conf")
    local password=$(jq -r --arg tag "$tag" '.inbounds[] | select(.tag == $tag) | .users[0].password' "$conf")
    local sni=$(jq -r --arg tag "$tag" '.inbounds[] | select(.tag == $tag) | .tls.server_name' "$conf")
    if [[ -z "$port" || "$port" == "null" || -z "$password" || "$password" == "null" ]]; then echo "N/A"; return; fi
    local link="hysteria2://${password}@${ip}:${port}?sni=${sni}&insecure=1#HY2_${ip}_${id}"
    echo "$link"
}

# -----------------------------------------------------------------------------
# 查看 UDP2RAW 客户端配置
# -----------------------------------------------------------------------------
view_udp2raw_client_config(){
    local id=$1; local conf="$UDP2RAW_INSTALL_DIR/udp2raw_${id}.conf"; if [[ ! -s "$conf" ]]; then red "错误: 未找到实例 $id 的配置文件或文件为空。"; return; fi
    local ip=$(get_instance_server_addr "udp2raw" "$id"); local port=$(get_listen_info_from_conf "$conf" | awk -F':' '{print $NF}'); local password=$(grep -Po '(?<=-k )[^ ]+' "$conf")
    
    cyan "--- UDP2RAW 实例 ${id} 客户端配置 ---";  echo
    green "${UDP2RAW_CLIENT_BASE_ARGS} -r ${ip}:${port} -l ${CLIENT_UDP2RAW_LISTEN_ADDR} -k ${password}"
}

# -----------------------------------------------------------------------------
# 查看 KCPTUN 客户端配置
# -----------------------------------------------------------------------------
view_kcptun_client_config(){
    local id=$1; local conf="$KCP_INSTALL_DIR/kcptun_${id}.json"; if [[ ! -s "$conf" ]]; then red "错误: 未找到实例 $id 的配置文件或文件为空。"; return; fi
    if ! command -v jq &>/dev/null; then red "错误: jq 未安装，无法解析配置。"; return; fi
    local ip=$(get_instance_server_addr "kcptun" "$id"); local server_listen=$(jq -r '.listen' "$conf"); local server_port=$(echo "$server_listen" | awk -F':' '{print $NF}')
    # KCPTUN 客户端 sndwnd/rcvwnd 需与服务器互换 (server.sndwnd <-> client.rcvwnd)
    local server_sndwnd=$(jq -r '.sndwnd' "$conf"); local server_rcvwnd=$(jq -r '.rcvwnd' "$conf")
    cyan "--- KCPTUN 实例 ${id} 客户端配置 ---"; echo
    yellow "方法一: 使用 JSON 配置文件 (推荐)"; yellow "将以下内容保存为客户端的 config.json (本地监听地址 ${CLIENT_KCPTUN_LISTEN_ADDR} 可自行修改):"; green "$(jq --arg listen "${CLIENT_KCPTUN_LISTEN_ADDR}" --arg target "${ip}:${server_port}" --argjson sndwnd "$server_rcvwnd" --argjson rcvwnd "$server_sndwnd" '.listen = $listen | .target = $target | .sndwnd = $sndwnd | .rcvwnd = $rcvwnd' "$conf")"; echo
    yellow "方法二: 使用命令行参数"; yellow "在客户端使用以下命令行参数 (本地监听地址 ${CLIENT_KCPTUN_LISTEN_ADDR} 可自行修改):";local args="-l ${CLIENT_KCPTUN_LISTEN_ADDR} -r ${ip}:${server_port}"
    for key in $(jq -r 'keys_unsorted | .[]' "$conf"); do
        if [[ "$key" == "sndwnd" ]]; then args+=" --${key} ${server_rcvwnd}"
        elif [[ "$key" == "rcvwnd" ]]; then args+=" --${key} ${server_sndwnd}"
        elif [[ "$key" != "listen" && "$key" != "target" ]]; then local value=$(jq -r --arg k "$key" '.[$k]' "$conf"); args+=" --${key} ${value}"; fi
    done; green "$args"; echo
}

