                read -p "请输入您想管理的实例序号: " manage_id_num; local mapped_id="${CHAIN_MAP[$manage_id_num]}"; if [[ -n "$mapped_id" ]]; then manage_chain_instance "$chain_type" "$mapped_id"; else red "无效的实例序号！"; sleep 2; fi;;
