# -----------------------------------------------------------------------------
# 独立实例总管理菜单 (循环)
# -----------------------------------------------------------------------------
main_manager_loop() {
    local type=$1; local title dir pattern service_prefix type_lowercase
    case $type in 
        udp2raw) title="UDP2RAW (独立)"; dir="$UDP2RAW_INSTALL_DIR"; pattern="udp2raw_*.conf"; service_prefix="udp2raw"; type_lowercase="udp2raw";;
        kcptun) title="KCPTUN (独立)"; dir="$KCP_INSTALL_DIR"; pattern="kcptun_*.json"; service_prefix="kcptun"; type_lowercase="kcptun";;
        xray_reality) title="VLESS+Reality"; dir="$SINGBOX_INSTALL_DIR"; pattern=""; service_prefix="ax-singbox"; type_lowercase="xray_reality";;
        hysteria2) title="Hysteria2"; dir="$SINGBOX_INSTALL_DIR"; pattern=""; service_prefix="ax-singbox"; type_lowercase="hysteria2";;
    esac
    while true; do
        trap 'echo -e "\n\n${yellow}操作已取消, 返回上级菜单...${reset}"; sleep 1; return' SIGINT
        clear; echo "=================================="; echo "     安装/管理 $title"; echo "=================================="; echo
        
        local INSTANCES=($(get_standalone_instances "$type_lowercase"))

        if [[ ${#INSTANCES[@]} -gt 0 ]]; then
            echo "$(bold "--- 现有实例 ---")"; for i in "${INSTANCES[@]}"; do display_instance_status_line "$type_lowercase" "$i" "  "; done
        else
            yellow "当前没有已创建的 $title 实例。"
        fi

        echo "----------------------------------"; local menu_options=("1) 新建实例" "2) 管理已有实例")
        if [[ "$type" == "xray_reality" || "$type" == "hysteria2" ]]; then menu_options+=("3) 查看订阅链接");
        elif [[ "$type" == "udp2raw" || "$type" == "kcptun" ]]; then menu_options+=("3) 查看客户端配置"); fi
        menu_options+=("0) 返回主菜单"); for opt in "${menu_options[@]}"; do echo "$opt"; done
        read -p "请选择: " choice
        case $choice in
            1)
                add_singbox_inbound "$type_lowercase"
                read -p $'\n按任意键返回...' -n1 -s;;
            2)
                if [[ ${#INSTANCES[@]} -eq 0 ]]; then yellow "当前没有可管理的实例。"; sleep 2; continue; fi
                echo "$(bold "可用实例:")"; local ii; for ii in "${INSTANCES[@]}"; do display_instance_status_line "$type_lowercase" "$ii" "  "; done
                local manage_id; read -p "请输入您想管理的实例ID: " manage_id; local is_valid=false; for id in "${INSTANCES[@]}"; do if [[ "$id" == "$manage_id" ]]; then is_valid=true; break; fi; done
                if [[ "$is_valid" == true ]]; then
                    local conf_path="$SINGBOX_INSTALL_DIR/singbox.json"
                    manage_instance_menu "$type_lowercase" "$manage_id" "ax-singbox" "$conf_path"
                else red "无效的实例ID！"; sleep 2; fi;;
             3)
                if [[ ${#INSTANCES[@]} -eq 0 ]]; then yellow "当前没有实例可供查看。"; sleep 2; continue; fi
                if [[ "$type" == "xray_reality" || "$type" == "hysteria2" ]]; then
                    for id in "${INSTANCES[@]}"; do
                        case "$type" in
                            xray_reality) cyan "$(generate_singbox_reality_link "$id")" ;;
                            hysteria2) cyan "$(generate_singbox_hy2_link "$id")" ;;
                        esac
                    done
                else
                    echo "$(bold "可用实例:")"; local ii; for ii in "${INSTANCES[@]}"; do display_instance_status_line "$type_lowercase" "$ii" "  "; done
                    local view_id; read -p "请输入您想查看的实例ID: " view_id; local is_valid=false; for id in "${INSTANCES[@]}"; do if [[ "$id" == "$view_id" ]]; then is_valid=true; break; fi; done
                    if [[ "$is_valid" == true ]]; then
                        case "$type" in
                            udp2raw) view_udp2raw_client_config "$view_id" ;;
                            kcptun) view_kcptun_client_config "$view_id" ;;
                        esac
                    else red "无效的实例ID！"; fi
                fi
                read -p $'\n按任意键返回...' -n1 -s;;
            0) break;; *) red "无效输入"; sleep 1;;
        esac
    done; trap - SIGINT
}

