# -----------------------------------------------------------------------------
# [新] 显示全局 TLS 证书状态
# -----------------------------------------------------------------------------
show_global_tls_status() {
    echo "--- TLS 证书状态 ---"
    
    # 检查 ACME 证书目录
    if [ ! -d "$AX_CERT_DIR" ] || [ -z "$(ls -A $AX_CERT_DIR)" ]; then
        yellow "未找到 ACME 证书。"
    else
        # 遍历 $AX_CERT_DIR 下的每个域名目录
        for domain_dir in "$AX_CERT_DIR"/*; do
            if [ -d "$domain_dir" ]; then
                local domain=$(basename "$domain_dir")
                local cert_file="$domain_dir/fullchain.cer"
                local key_file="$domain_dir/private.key"
                
                if [ -f "$cert_file" ] && [ -f "$key_file" ]; then
                    local expiry_date_str
                    local days_remaining="N/A"
                    
                    # 尝试获取到期天数
                    if command -v openssl &>/dev/null; then
                        expiry_date_str=$(openssl x509 -in "$cert_file" -noout -enddate 2>/dev/null | cut -d= -f2)
                        if [ -n "$expiry_date_str" ]; then
                            local expiry_epoch=$(date -d "$expiry_date_str" +%s 2>/dev/null)
                            local now_epoch=$(date +%s)
                            if [ -n "$expiry_epoch" ]; then
                                days_remaining=$(((expiry_epoch - now_epoch) / 86400))
                                days_remaining="(剩余 ${days_remaining} 天)"
                            fi
                        fi
                    fi
                    
                    cyan "[域名] $domain $days_remaining"
                    echo "  公钥 (Cert): $cert_file"
                    echo "  私钥 (Key):  $key_file"
                fi
            fi
        done
    fi
}

# -----------------------------------------------------------------------------
# [新] 显示 WARP 状态
# -----------------------------------------------------------------------------
show_warp_status() {
    echo "--- WARP 状态 ---"
    local warp_addr=$(jq -r '.endpoints[] | select(.tag == "warp-ep") | .address // empty' "$SINGBOX_INSTALL_DIR/singbox.json" 2>/dev/null)
    warp_addr="${warp_addr%/*}"
    if [[ -n "$warp_addr" ]]; then
        # 确保 mixed inbound 存在（升级兼容）
        if ! jq -e '.inbounds[] | select(.tag == "mixed-in")' "$SINGBOX_INSTALL_DIR/singbox.json" >/dev/null 2>&1; then
            python3 -c "
import json
cfg = json.load(open('$SINGBOX_INSTALL_DIR/singbox.json'))
cfg.setdefault('inbounds', []).append({'type': 'mixed', 'tag': 'mixed-in', 'listen': '127.0.0.1', 'listen_port': 17888})
json.dump(cfg, open('$SINGBOX_INSTALL_DIR/singbox.json','w'), indent=2)
" 2>/dev/null && systemctl restart ax-singbox.service 2>/dev/null
        fi
        local real_ip=$(curl -s --max-time 5 --socks5-hostname 127.0.0.1:17888 http://ip-api.com/json/ 2>/dev/null | jq -r '.query // empty')
        if [[ -n "$real_ip" ]]; then
            green "WARP 分流: 已启用 (出口: $real_ip)"
        else
            green "WARP 分流: 已启用 ($warp_addr)"
        fi
    else
        yellow "WARP 分流: 未启用"
    fi
}

